insert into public.cards (event_id, front, back, difficulty) values
  ('a1000000-0000-0000-0000-000000000001', 'What does the prefix "hyper-" mean?', 'Excessive, above normal (e.g., hypertension = high blood pressure)', 'easy'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the prefix "hypo-" mean?', 'Below normal, deficient (e.g., hypoglycemia = low blood sugar)', 'easy'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the suffix "-itis" mean?', 'Inflammation (e.g., appendicitis = inflammation of the appendix)', 'easy'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the suffix "-ectomy" mean?', 'Surgical removal (e.g., appendectomy = surgical removal of the appendix)', 'easy'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the suffix "-ology" mean?', 'Study of (e.g., cardiology = study of the heart)', 'easy'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the prefix "brady-" mean?', 'Slow (e.g., bradycardia = slow heart rate)', 'easy'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the prefix "tachy-" mean?', 'Fast, rapid (e.g., tachycardia = rapid heart rate)', 'easy'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the suffix "-emia" mean?', 'Blood condition (e.g., anemia = deficiency of red blood cells in the blood)', 'easy'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the root "cardi/o" refer to?', 'Heart (e.g., cardiology, cardiomyopathy)', 'easy'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the root "derm/o" refer to?', 'Skin (e.g., dermatology, dermatitis)', 'easy'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the suffix "-algia" mean?', 'Pain (e.g., myalgia = muscle pain, neuralgia = nerve pain)', 'easy'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the suffix "-osis" mean?', 'Abnormal condition or process (e.g., fibrosis = abnormal fibrous tissue formation)', 'easy'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the prefix "poly-" mean?', 'Many, much (e.g., polyuria = excessive urination)', 'easy'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the root "nephr/o" refer to?', 'Kidney (e.g., nephrology, nephritis)', 'easy'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the root "hepat/o" refer to?', 'Liver (e.g., hepatitis, hepatomegaly)', 'easy'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the suffix "-scope" mean?', 'Instrument used for visual examination (e.g., endoscope, stethoscope)', 'easy'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the root "oste/o" refer to?', 'Bone (e.g., osteoporosis, osteomyelitis)', 'easy'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the prefix "ante-" mean?', 'Before, in front of (e.g., antepartum = before birth)', 'easy'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the prefix "post-" mean?', 'After, behind (e.g., postoperative = after surgery)', 'easy'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the suffix "-pathy" mean?', 'Disease, suffering (e.g., cardiomyopathy = disease of heart muscle)', 'easy');
insert into public.cards (event_id, front, back, difficulty) values
  ('a1000000-0000-0000-0000-000000000001', 'Define "dyspnea."', 'Difficulty or painful breathing; shortness of breath. Dys- (painful/difficult) + -pnea (breathing).', 'medium'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "tachycardia."', 'Abnormally rapid heart rate, typically defined as greater than 100 beats per minute in adults.', 'medium'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "bradycardia."', 'Abnormally slow heart rate, typically defined as fewer than 60 beats per minute in adults.', 'medium'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "hematuria."', 'Presence of blood in the urine. Hemat/o (blood) + -uria (urine condition).', 'medium'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "cholecystectomy."', 'Surgical removal of the gallbladder. Chole- (bile) + cyst- (bladder/sac) + -ectomy (removal).', 'medium'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "electrocardiogram (ECG/EKG)."', 'A recording of the electrical activity of the heart over time; used to detect arrhythmias, MI, and conduction abnormalities.', 'medium'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "thrombocyte."', 'Platelet; a small, anucleate blood cell fragment that plays a central role in hemostasis and blood clot formation.', 'medium'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "erythrocyte."', 'Red blood cell; the most abundant blood cell type that carries oxygen via hemoglobin and carbon dioxide back to the lungs.', 'medium'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "leukocyte."', 'White blood cell; a cell of the immune system that defends the body against infection, allergy, and foreign substances.', 'medium'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "anemia."', 'A condition in which the blood is deficient in red blood cells, hemoglobin, or total blood volume; results in reduced oxygen-carrying capacity.', 'medium'),
  ('a1000000-0000-0000-0000-000000000001', 'What does "subcutaneous" mean?', 'Beneath the skin; pertaining to the tissue layer directly under the dermis. Sub- (under) + cutane/o (skin) + -ous (pertaining to).', 'medium'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "arthroscopy."', 'Visual examination of the interior of a joint using a fiber-optic arthroscope; used for diagnosis and surgery of joint disorders.', 'medium'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "myalgia."', 'Muscle pain or tenderness. My/o (muscle) + -algia (pain).', 'medium'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "rhinoplasty."', 'Surgical repair or reconstruction of the nose. Rhin/o (nose) + -plasty (surgical repair).', 'medium'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "endoscopy."', 'Visual examination of the interior of a body cavity or hollow organ using a flexible or rigid endoscope; includes colonoscopy, bronchoscopy, and EGD.', 'medium'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "cyanosis."', 'A bluish or purplish discoloration of the skin, lips, and mucous membranes caused by insufficient oxygenation of the blood (low SpO2).', 'medium'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "hemostasis."', 'The process of stopping bleeding; includes vasoconstriction, platelet plug formation, and the coagulation cascade.', 'medium'),
  ('a1000000-0000-0000-0000-000000000001', 'What does the term "bilateral" mean?', 'Pertaining to or affecting both sides of the body or both of a paired organ (e.g., bilateral pneumonia).', 'medium'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "edema."', 'Abnormal accumulation of excess fluid in the interstitial space of body tissues, causing swelling; can be localized or generalized.', 'medium'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "gastroenteritis."', 'Inflammation of the stomach and small intestine, usually caused by viral or bacterial infection; presents with nausea, vomiting, and diarrhea.', 'medium');
insert into public.cards (event_id, front, back, difficulty) values
  ('a1000000-0000-0000-0000-000000000001', 'Define "pneumonoultramicroscopicsilicovolcanoconiosis."', 'A lung disease caused by the inhalation of very fine silica or quartz dust from volcanic ash; a form of pneumoconiosis. One of the longest words in the English language.', 'hard'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "sphygmomanometer."', 'An instrument used to measure arterial blood pressure; consists of an inflatable cuff, pressure gauge, and stethoscope.', 'hard'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "encephalomyelitis."', 'Inflammation of both the brain (encephalon) and the spinal cord (myelos); can be caused by viral infections or autoimmune processes (e.g., MS).', 'hard'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "thrombophlebitis."', 'Inflammation of a vein accompanied by or caused by a blood clot; most common in the legs; risk of embolism if clot dislodges.', 'hard'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "pericardiocentesis."', 'Surgical puncture of the pericardial sac (the membrane surrounding the heart) to withdraw excess fluid; used for cardiac tamponade.', 'hard'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "electroencephalography."', 'The process of recording the electrical activity of the brain using electrodes placed on the scalp (EEG); used to diagnose seizure disorders, sleep disorders, and brain death.', 'hard'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "cholangiopancreatography."', 'Radiographic examination of the bile ducts and pancreatic duct, typically performed as ERCP (endoscopic retrograde cholangiopancreatography) to diagnose and treat biliary and pancreatic pathology.', 'hard'),
  ('a1000000-0000-0000-0000-000000000001', 'Differentiate the suffixes "-plasty" and "-pexy."', '-plasty: surgical repair or reconstruction of a structure (e.g., rhinoplasty). -pexy: surgical fixation of an organ to prevent prolapse (e.g., orchiopexy = surgical fixation of an undescended testis).', 'hard'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "epistaxis."', 'Nosebleed; hemorrhage from the nasal mucosa. Epistaxis is the medical term; anterior bleeds (Kiesselbach''s plexus) are most common.', 'hard'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "diaphoresis."', 'Profuse sweating, often associated with fever, shock, myocardial infarction, or autonomic nervous system activation.', 'hard'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "ptosis."', 'Drooping or sagging of an organ or body part; most commonly refers to drooping of the upper eyelid due to weakness of the levator palpebrae superioris muscle or CN III palsy.', 'hard'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "borborygmus."', 'A rumbling or gurgling noise produced by the movement of gas through the intestines; a normal sound audible with a stethoscope or sometimes even without.', 'hard'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "pneumothorax."', 'Accumulation of air or gas in the pleural space between the lung and chest wall, causing the lung to collapse. Can be spontaneous, traumatic, or tension (life-threatening).', 'hard'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "paracentesis."', 'Surgical puncture of a body cavity (usually the abdomen/peritoneal cavity) to remove accumulated fluid (ascites) for diagnostic or therapeutic purposes.', 'hard'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "hemoglobinopathy."', 'Any genetic disorder affecting the structure or production of hemoglobin; examples include sickle cell disease (abnormal HbS) and thalassemia (reduced globin chain synthesis).', 'hard'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "otorhinolaryngology."', 'The medical specialty dealing with disorders of the ear (oto-), nose (rhino-), and throat/larynx (-laryngology); commonly abbreviated ENT.', 'hard'),
  ('a1000000-0000-0000-0000-000000000001', 'What is the difference between "supine" and "prone"?', 'Supine: lying on the back, face upward. Prone: lying face downward. A helpful mnemonic: you "sup" (eat) face up, and "prone" to falling face down.', 'hard'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "idiopathic."', 'Relating to a disease or condition arising spontaneously or from an unknown cause; no identifiable underlying etiology (e.g., idiopathic pulmonary fibrosis).', 'hard'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "iatrogenic."', 'Relating to illness, injury, or adverse effect caused by medical examination, treatment, or a healthcare provider (e.g., iatrogenic pneumothorax from central line insertion).', 'hard'),
  ('a1000000-0000-0000-0000-000000000001', 'Define "nosocomial."', 'Originating or acquired in a hospital or healthcare setting; a hospital-acquired (nosocomial) infection develops >48 hours after admission (e.g., MRSA, C. difficile, VAP).', 'hard');
insert into public.cards (event_id, front, back, difficulty) values
  ('a1000000-0000-0000-0000-000000000002', 'What is pathophysiology?', 'The study of how diseases alter normal body functions; combines pathology (study of disease) and physiology (study of function) to explain the mechanisms underlying illness.', 'easy'),
  ('a1000000-0000-0000-0000-000000000002', 'What is inflammation?', 'The body''s protective response to tissue injury or infection, characterized by redness (rubor), heat (calor), swelling (tumor), pain (dolor), and loss of function.', 'easy'),
  ('a1000000-0000-0000-0000-000000000002', 'What are the 5 cardinal signs of inflammation?', 'Redness (rubor), heat (calor), swelling (tumor), pain (dolor), and loss of function (functio laesa). The first four were described by Celsus; the fifth added by Virchow.', 'easy'),
  ('a1000000-0000-0000-0000-000000000002', 'What is an embolus?', 'A detached, intravascular mass (clot, fat droplet, air bubble, or foreign body) carried by the bloodstream until it lodges in a vessel too small to pass, causing obstruction.', 'easy'),
  ('a1000000-0000-0000-0000-000000000002', 'What is a thrombus?', 'A blood clot that forms inside a blood vessel and remains attached to the vessel wall; distinguished from an embolus which travels through the bloodstream.', 'easy'),
  ('a1000000-0000-0000-0000-000000000002', 'What is ischemia?', 'Inadequate blood supply to a tissue or organ causing oxygen deprivation (hypoxia) and nutrient deficiency; reversible if corrected quickly, leads to infarction if prolonged.', 'easy'),
  ('a1000000-0000-0000-0000-000000000002', 'What is necrosis?', 'Pathological cell and tissue death caused by external injury, ischemia, toxins, or infection; associated with cell membrane rupture and inflammation.', 'easy'),
  ('a1000000-0000-0000-0000-000000000002', 'What is apoptosis?', 'Programmed, controlled cell death that occurs as a normal part of development and tissue maintenance; no inflammation; cell shrinks and fragments are phagocytosed cleanly.', 'easy'),
  ('a1000000-0000-0000-0000-000000000002', 'What is edema?', 'Excess fluid accumulation in the interstitial space of body tissues causing swelling; results from increased capillary permeability, increased hydrostatic pressure, or decreased oncotic pressure.', 'easy'),
  ('a1000000-0000-0000-0000-000000000002', 'What is hypoxia?', 'A deficiency of oxygen reaching body tissues; types include hypoxic (low PaO2), anemic (reduced O2-carrying capacity), circulatory (poor perfusion), and histotoxic (cells cannot use O2).', 'easy'),
  ('a1000000-0000-0000-0000-000000000002', 'What is the difference between benign and malignant tumors?', 'Benign: noncancerous, slow-growing, well-encapsulated, does not invade or metastasize. Malignant: cancerous, invasive, poorly differentiated, capable of metastasizing to distant sites.', 'easy'),
  ('a1000000-0000-0000-0000-000000000002', 'What is metastasis?', 'The spread of cancer cells from the primary tumor to distant organs or tissues via the bloodstream (hematogenous), lymphatics, or direct extension.', 'easy'),
  ('a1000000-0000-0000-0000-000000000002', 'What is hypertension?', 'Persistently elevated arterial blood pressure; defined as systolic ≥130 mmHg or diastolic ≥80 mmHg (AHA 2017 guidelines); a major risk factor for stroke, MI, and kidney failure.', 'easy'),
  ('a1000000-0000-0000-0000-000000000002', 'What is atherosclerosis?', 'A progressive disease characterized by buildup of lipid-laden plaques (atheromas) within the intima of medium and large arteries, narrowing the lumen and reducing blood flow.', 'easy'),
  ('a1000000-0000-0000-0000-000000000002', 'What is an aneurysm?', 'A localized, abnormal dilation (bulge) of a blood vessel wall due to weakness; can be saccular (berry-shaped) or fusiform; risk of rupture causing life-threatening hemorrhage.', 'easy'),
  ('a1000000-0000-0000-0000-000000000002', 'What is diabetes mellitus?', 'A chronic metabolic disorder characterized by hyperglycemia due to defects in insulin secretion, insulin action, or both; leads to long-term damage to eyes, kidneys, nerves, and blood vessels.', 'easy'),
  ('a1000000-0000-0000-0000-000000000002', 'What is the difference between Type 1 and Type 2 diabetes?', 'Type 1: autoimmune destruction of pancreatic beta cells → absolute insulin deficiency; requires insulin therapy. Type 2: insulin resistance with relative insulin deficiency; linked to obesity, managed with lifestyle and oral medications.', 'easy'),
  ('a1000000-0000-0000-0000-000000000002', 'What is an autoimmune disease?', 'A condition in which the immune system fails to recognize self-antigens and launches an attack against the body''s own healthy cells and tissues (e.g., rheumatoid arthritis, lupus, MS, type 1 diabetes).', 'easy'),
  ('a1000000-0000-0000-0000-000000000002', 'What is sepsis?', 'A life-threatening organ dysfunction caused by a dysregulated host response to infection; requires organ dysfunction (SOFA score ≥2) beyond simple infection to meet definition.', 'easy'),
  ('a1000000-0000-0000-0000-000000000002', 'What is a myocardial infarction?', 'Heart attack; irreversible death of cardiac muscle tissue caused by prolonged ischemia, typically from occlusion of a coronary artery by a ruptured atherosclerotic plaque and thrombus.', 'easy');
insert into public.cards (event_id, front, back, difficulty) values
  ('a1000000-0000-0000-0000-000000000002', 'Describe the pathophysiology of asthma.', 'Chronic airway inflammation leads to bronchial hyperresponsiveness. Triggers cause mast cell degranulation → histamine and leukotriene release → bronchospasm, mucus hypersecretion, and airway edema → reversible airflow obstruction, wheezing, and dyspnea.', 'medium'),
  ('a1000000-0000-0000-0000-000000000002', 'Describe the pathophysiology of congestive heart failure (CHF).', 'The heart cannot pump sufficient blood to meet metabolic demands. Forward failure: decreased cardiac output → organ hypoperfusion. Backward failure: fluid congestion → pulmonary edema (left-sided) or peripheral edema/JVD (right-sided). RAAS and SNS activation worsen the cycle.', 'medium'),
  ('a1000000-0000-0000-0000-000000000002', 'What is disseminated intravascular coagulation (DIC)?', 'A life-threatening condition of widespread, uncontrolled activation of the coagulation cascade leading to simultaneous diffuse clot formation AND hemorrhage due to consumption of platelets and clotting factors. Triggered by sepsis, trauma, obstetric complications, or malignancy.', 'medium'),
  ('a1000000-0000-0000-0000-000000000002', 'What is the renin-angiotensin-aldosterone system (RAAS)?', 'A hormonal cascade regulating BP and fluid balance. Low BP/volume → kidneys release renin → angiotensinogen → angiotensin I → ACE converts to angiotensin II → vasoconstriction + aldosterone release → Na+/H2O retention → increased BP and volume.', 'medium'),
  ('a1000000-0000-0000-0000-000000000002', 'What is acute respiratory distress syndrome (ARDS)?', 'A severe form of diffuse lung injury characterized by: rapid onset, bilateral pulmonary infiltrates, refractory hypoxemia (PaO2/FiO2 <300), and NOT explained by cardiac failure. Caused by sepsis, pneumonia, aspiration, or trauma. Diffuse alveolar damage disrupts the alveolocapillary membrane.', 'medium'),
  ('a1000000-0000-0000-0000-000000000002', 'What is the pathophysiology of a stroke?', 'Ischemic (85%): occlusion of a cerebral artery by thrombus or embolism → neuronal death from lack of oxygen and glucose. Hemorrhagic (15%): rupture of a cerebral vessel → direct tissue destruction and increased ICP. Both cause focal neurological deficits corresponding to the affected brain region.', 'medium'),
  ('a1000000-0000-0000-0000-000000000002', 'What is cirrhosis?', 'Chronic, irreversible end-stage liver disease characterized by replacement of normal hepatic parenchyma with fibrous scar tissue and regenerative nodules, causing portal hypertension, impaired synthetic function, and eventual liver failure.', 'medium'),
  ('a1000000-0000-0000-0000-000000000002', 'What is the pathophysiology of chronic kidney disease (CKD)?', 'Progressive, irreversible loss of nephron function (measured by GFR) over months to years from diabetes, hypertension, or glomerulonephritis. Results in fluid/electrolyte imbalances, uremia (waste accumulation), anemia (↓EPO), renal osteodystrophy (↓activated vitamin D), and hypertension.', 'medium'),
  ('a1000000-0000-0000-0000-000000000002', 'What is Cushing syndrome?', 'A condition caused by prolonged exposure to excess cortisol (endogenous from a pituitary/adrenal tumor, or exogenous from corticosteroid therapy). Features: central obesity, moon face, buffalo hump, striae, hypertension, hyperglycemia, osteoporosis, and immunosuppression.', 'medium'),
  ('a1000000-0000-0000-0000-000000000002', 'What is Addison disease?', 'Primary adrenocortical insufficiency caused by autoimmune destruction of the adrenal cortex → inadequate cortisol and aldosterone production. Presents with fatigue, hypotension, hyperpigmentation (↑ACTH stimulates melanocytes), hyponatremia, hyperkalemia, and hypoglycemia.', 'medium'),
  ('a1000000-0000-0000-0000-000000000002', 'What is the pathophysiology of pneumonia?', 'Infectious agents (bacteria, viruses, fungi) invade the lower respiratory tract → inflammatory exudate fills alveoli (consolidation) → V/Q mismatch and impaired gas exchange → hypoxemia, fever, productive cough, and increased work of breathing.', 'medium'),
  ('a1000000-0000-0000-0000-000000000002', 'Describe the pathophysiology of deep vein thrombosis (DVT).', 'Clot formation in deep veins (usually lower extremities) driven by Virchow''s triad: (1) venous stasis (immobility, heart failure), (2) endothelial injury (trauma, surgery), (3) hypercoagulability (cancer, pregnancy, factor V Leiden). Risk: pulmonary embolism if clot dislodges.', 'medium'),
  ('a1000000-0000-0000-0000-000000000002', 'What is Virchow''s triad?', 'Three factors predisposing to thrombosis: (1) Venous stasis — slow/turbulent blood flow; (2) Endothelial injury — damage to vessel lining; (3) Hypercoagulability — abnormal clotting tendency. Named after Rudolf Virchow (1856).', 'medium'),
  ('a1000000-0000-0000-0000-000000000002', 'What is the pathophysiology of sickle cell disease?', 'A mutation in the beta-globin gene produces hemoglobin S (HbS). Under low O2 conditions, HbS polymerizes → red cells sickle → rigid, sticky cells occlude microvasculature → vaso-occlusive crises (pain), hemolytic anemia, and organ damage (spleen, kidneys, brain).', 'medium'),
  ('a1000000-0000-0000-0000-000000000002', 'What is the pathophysiology of multiple sclerosis?', 'Autoimmune T-cell-mediated attack on oligodendrocytes and myelin sheaths in the CNS → demyelination → impaired saltatory conduction → varied neurological symptoms (vision loss, weakness, spasticity, ataxia). Lesions are disseminated in space and time.', 'medium'),
  ('a1000000-0000-0000-0000-000000000002', 'What is anaphylaxis?', 'A severe, life-threatening systemic allergic reaction (Type I hypersensitivity). IgE-mediated mast cell and basophil degranulation releases massive histamine → vasodilation, increased vascular permeability, bronchoconstriction → distributive shock, airway compromise, and potential death.', 'medium'),
  ('a1000000-0000-0000-0000-000000000002', 'What is the pathophysiology of hepatitis?', 'Inflammation of the liver from viral infection (Hep A/B/C/D/E), alcohol, drugs, or autoimmune processes → hepatocyte injury and necrosis → impaired liver functions (detoxification, protein synthesis, bile production). Chronic hepatitis can progress to cirrhosis and hepatocellular carcinoma.', 'medium'),
  ('a1000000-0000-0000-0000-000000000002', 'What is the difference between systolic and diastolic heart failure?', 'Systolic (HFrEF): reduced ejection fraction (<40%) from impaired ventricular contraction; heart cannot squeeze adequately. Diastolic (HFpEF): preserved ejection fraction (≥50%) but impaired ventricular relaxation/filling; heart cannot fill adequately. Both cause similar symptoms.', 'medium'),
  ('a1000000-0000-0000-0000-000000000002', 'What is shock?', 'A life-threatening state of inadequate tissue perfusion causing cellular hypoxia and organ dysfunction. Types: Hypovolemic (↓volume), Cardiogenic (↓pump function), Distributive (maldistribution: septic/anaphylactic/neurogenic), Obstructive (blocked flow: PE/tamponade/tension PTX).', 'medium'),
  ('a1000000-0000-0000-0000-000000000002', 'What is the pathophysiology of COPD?', 'Chronic Bronchitis: persistent airway inflammation → mucus hypersecretion → mucus plugging and airflow obstruction. Emphysema: destruction of alveolar walls and loss of elastic recoil → air trapping and hyperinflation. Both: progressive, largely irreversible airflow limitation.', 'medium');
insert into public.cards (event_id, front, back, difficulty) values
  ('a1000000-0000-0000-0000-000000000002', 'Explain the complement cascade.', 'A series of ~30 plasma proteins (C1–C9) activated sequentially (classical, lectin, or alternative pathway) to enhance immune defense through: (1) opsonization (C3b coating pathogens for phagocytosis), (2) chemotaxis (C5a attracting neutrophils), (3) membrane attack complex (MAC, C5b-9) lysing pathogens, and (4) inflammation amplification.', 'hard'),
  ('a1000000-0000-0000-0000-000000000002', 'Describe the pathophysiology of acute kidney injury (AKI).', 'Prerenal: decreased renal perfusion (hypovolemia, heart failure, sepsis) → reduced GFR. Intrarenal: direct kidney damage from nephrotoxins, ischemia, glomerulonephritis, or interstitial nephritis. Postrenal: obstruction of urinary outflow (stones, BPH). All cause rapid rise in creatinine and BUN with decline in GFR.', 'hard'),
  ('a1000000-0000-0000-0000-000000000002', 'What is the pathophysiology of pulmonary embolism?', 'Usually a DVT thrombus embolizes to the pulmonary vasculature → obstruction of pulmonary arteries → increased pulmonary vascular resistance → right heart strain → V/Q mismatch → hypoxemia. Massive PE: obstructive shock from RV failure, hemodynamic collapse, and cardiac arrest.', 'hard'),
  ('a1000000-0000-0000-0000-000000000002', 'Explain the pathophysiology of diabetic ketoacidosis (DKA).', 'Absolute insulin deficiency (Type 1 DM trigger) → unregulated lipolysis releases free fatty acids → liver converts to ketone bodies (beta-hydroxybutyrate, acetoacetate, acetone) → metabolic acidosis (↓pH, ↓HCO3). Simultaneously: hyperglycemia causes osmotic diuresis → dehydration + electrolyte loss (K+, Na+).', 'hard'),
  ('a1000000-0000-0000-0000-000000000002', 'What is tumor lysis syndrome?', 'A metabolic emergency following rapid cancer cell lysis (usually after chemotherapy) releasing intracellular contents: Hyperkalemia (cardiac arrest risk), Hyperphosphatemia (→hypocalcemia → tetany/seizures), Hyperuricemia (→urate nephropathy → AKI). Prevention: aggressive hydration and allopurinol/rasburicase.', 'hard'),
  ('a1000000-0000-0000-0000-000000000002', 'Describe the inflammatory cascade in detail.', 'Injury/infection → mast cell degranulation (histamine, heparin) → arachidonic acid pathway activation (COX → prostaglandins; LOX → leukotrienes) → vasodilation and increased vascular permeability → complement activation (opsonization, MAC, chemotaxis) → cytokine storm (TNF-α, IL-1, IL-6) → leukocyte recruitment (neutrophils first, then macrophages) → phagocytosis and tissue repair.', 'hard'),
  ('a1000000-0000-0000-0000-000000000002', 'What is the pathophysiology of systemic lupus erythematosus (SLE)?', 'Failure of self-tolerance → production of autoantibodies (anti-dsDNA, anti-Smith, anti-Ro, anti-La) → immune complex (Type III hypersensitivity) formation and deposition in kidneys (nephritis), joints, skin (malar rash), and serous membranes → complement activation → local inflammation and organ damage.', 'hard'),
  ('a1000000-0000-0000-0000-000000000002', 'Explain the pathophysiology of heart failure with reduced ejection fraction (HFrEF).', 'Myocardial damage (MI, cardiomyopathy) → ↓contractility → ↓stroke volume/cardiac output → compensatory RAAS activation (fluid retention, vasoconstriction) and SNS activation (tachycardia, ↑contractility) → initially helpful but chronically cause ventricular remodeling, ↑wall stress, and further myocardial dysfunction — a vicious cycle.', 'hard'),
  ('a1000000-0000-0000-0000-000000000002', 'What is rhabdomyolysis?', 'Rapid breakdown of skeletal muscle from trauma, prolonged immobility, seizures, extreme exertion, or drugs (statins, alcohol) → myoglobin, CK, potassium, and phosphate released into circulation. Myoglobin precipitates in renal tubules → obstructive AKI. Treat with aggressive IV fluids to maintain urine output >200–300 mL/hr.', 'hard'),
  ('a1000000-0000-0000-0000-000000000002', 'Describe the pathophysiology of thyroid storm.', 'A life-threatening exacerbation of hyperthyroidism (precipitated by surgery, infection, or iodine load) → massive thyroid hormone release → profound hypermetabolism: hyperthermia (>40°C), tachyarrhythmias, heart failure, diaphoresis, agitation, and multi-organ dysfunction. Mortality 10–30% even with treatment.', 'hard'),
  ('a1000000-0000-0000-0000-000000000002', 'What is the pathophysiology of status epilepticus?', 'Sustained seizure activity (>5 minutes) from failure of inhibitory GABAergic mechanisms and excessive glutamatergic (NMDA) excitation → prolonged neuronal depolarization → ATP depletion, excitotoxicity, cerebral edema, hyperthermia, rhabdomyolysis, metabolic acidosis, and irreversible neuronal injury. Treat urgently with benzodiazepines then phenytoin/levetiracetam.', 'hard'),
  ('a1000000-0000-0000-0000-000000000002', 'Explain the Frank-Starling mechanism.', 'The heart''s intrinsic ability to increase stroke volume in response to greater ventricular filling (preload). As sarcomeres are stretched by increased end-diastolic volume, myosin-actin crossbridge formation is optimized, producing a stronger contraction — up to a physiological limit beyond which further stretch reduces output (as in severe heart failure).', 'hard'),
  ('a1000000-0000-0000-0000-000000000002', 'What is the pathophysiology of compartment syndrome?', 'Increased pressure within a closed fascial compartment (from bleeding, edema, or external compression) compromises capillary perfusion. Tissue ischemia → more edema → further pressure rise (vicious cycle). Without emergent fasciotomy: nerve and muscle necrosis, permanent disability, and loss of limb. Classic 6 Ps: Pain, Pressure, Paresthesia, Paralysis, Pallor, Pulselessness (late).', 'hard'),
  ('a1000000-0000-0000-0000-000000000002', 'Describe the pathophysiology of Guillain-Barré syndrome.', 'Post-infectious autoimmune attack (often after Campylobacter jejuni, CMV, or Zika) on peripheral nerve myelin (AIDP subtype) or axons (AMAN/AMSAN subtypes). Molecular mimicry between pathogen antigens and nerve components triggers T-cell and antibody-mediated demyelination → ascending weakness and areflexia, potentially involving respiratory muscles (30% need ventilation).', 'hard'),
  ('a1000000-0000-0000-0000-000000000002', 'What is the pathophysiology of acute pancreatitis?', 'Premature, intrapancreatic activation of trypsinogen to trypsin (from gallstones blocking ampulla, alcohol, or hypercalcemia) → autodigestion of pancreatic tissue → local inflammation, edema, and potentially hemorrhagic necrosis. Systemic SIRS can progress to multi-organ failure in severe cases.', 'hard'),
  ('a1000000-0000-0000-0000-000000000002', 'Explain the role of RAAS in chronic heart failure.', 'Decreased cardiac output → reduced renal perfusion → renin release → angiotensin II (vasoconstriction raises afterload) + aldosterone (Na+/H2O retention raises preload and volume). Short-term: beneficial compensation. Long-term: excessive afterload and preload → further myocardial stretch and remodeling → progressive heart failure. ACE inhibitors and ARBs block this cycle therapeutically.', 'hard'),
  ('a1000000-0000-0000-0000-000000000002', 'What is hepatorenal syndrome?', 'Functional renal failure in advanced liver disease without structural kidney damage. Mechanism: splanchnic vasodilation (from portal hypertension and vasodilators like NO) → underfilling of systemic circulation → compensatory renal vasoconstriction → dramatically reduced renal blood flow and GFR. Treatment: vasoconstrictors (terlipressin) + albumin; liver transplant is definitive.', 'hard'),
  ('a1000000-0000-0000-0000-000000000002', 'Define and differentiate the four types of hypersensitivity reactions.', 'Type I (Immediate/Anaphylactic): IgE-mediated mast cell degranulation (e.g., anaphylaxis, asthma). Type II (Cytotoxic): IgG/IgM bind cell surface antigens → complement lysis or ADCC (e.g., hemolytic anemia, Goodpasture). Type III (Immune Complex): Ag-Ab complexes deposit in tissues → complement inflammation (e.g., SLE, serum sickness). Type IV (Delayed/Cell-Mediated): T-cell mediated, 24-72 hr delay (e.g., contact dermatitis, TB test, transplant rejection).', 'hard'),
  ('a1000000-0000-0000-0000-000000000002', 'What is the pathophysiology of cardiogenic shock?', 'Massive myocardial injury (large MI, myocarditis, decompensated CHF) → severely reduced stroke volume and cardiac output → tissue hypoperfusion. Compensatory SNS activation → tachycardia, vasoconstriction → increased myocardial oxygen demand on already failing heart → further ischemia. Simultaneously: pulmonary edema impairs oxygenation. Mortality ~40-50% even with PCI.', 'hard'),
  ('a1000000-0000-0000-0000-000000000002', 'Describe the pathophysiology of malignant hyperthermia.', 'A pharmacogenetic disorder (RYR1 mutation) triggered by volatile anesthetics (halothane, sevoflurane) or succinylcholine. Uncontrolled calcium release from sarcoplasmic reticulum → sustained muscle hypercontraction → hyperthermia (can exceed 43°C), profound metabolic acidosis, rhabdomyolysis, hyperkalemia, and multi-organ failure. Treatment: dantrolene (blocks SR Ca2+ release), cooling, and supportive care.', 'hard');
insert into public.cards (event_id, front, back, difficulty) values
  ('a1000000-0000-0000-0000-000000000003', 'What are the normal vital sign ranges for a healthy adult?', 'BP: <120/80 mmHg (normal), HR: 60-100 bpm, RR: 12-20 breaths/min, Temperature: 36.1-37.2°C (97-99°F) oral, SpO2: 95-100%.', 'easy'),
  ('a1000000-0000-0000-0000-000000000003', 'What are the Five Rights of medication administration?', 'Right Patient, Right Drug, Right Dose, Right Route, Right Time. Many sources add Right Documentation and Right Reason as additional rights.', 'easy'),
  ('a1000000-0000-0000-0000-000000000003', 'What is Fowler''s position?', 'The patient is in a semi-sitting position with the head of the bed elevated 45–60°. Used for respiratory distress, cardiac patients, post-operative recovery, and tube feedings.', 'easy'),
  ('a1000000-0000-0000-0000-000000000003', 'What is the semi-Fowler''s position?', 'Head of bed elevated 30–45°. Used for comfort, respiratory support, tube feeding administration, and nasogastric tube insertion. Reduces aspiration risk.', 'easy'),
  ('a1000000-0000-0000-0000-000000000003', 'What is the supine position?', 'Patient lies flat on the back, face upward. Used for spinal immobilization, most abdominal/thoracic surgery, CPR, and general assessment.', 'easy'),
  ('a1000000-0000-0000-0000-000000000003', 'What is normal urine output for an adult?', '0.5–1 mL/kg/hour, or approximately 30–60 mL/hour. Output <30 mL/hour indicates oliguria and may signal dehydration, renal failure, or hypoperfusion.', 'easy'),
  ('a1000000-0000-0000-0000-000000000003', 'What are the RACE steps in fire safety?', 'Rescue patients in immediate danger, Alarm (activate fire alarm/call 911), Confine the fire (close doors and windows), Extinguish the fire if safe or Evacuate.', 'easy'),
  ('a1000000-0000-0000-0000-000000000003', 'What does PASS stand for for fire extinguisher use?', 'Pull the pin, Aim at the base of the fire, Squeeze the handle, Sweep side to side across the base of the flames.', 'easy'),
  ('a1000000-0000-0000-0000-000000000003', 'What is the purpose of oxygen therapy?', 'To increase the fraction of inspired oxygen (FiO2) to correct hypoxemia (SpO2 <90%) and maintain adequate tissue oxygenation. Goal SpO2: 94-98% for most patients; 88-92% for COPD patients at risk of hypercapnia.', 'easy'),
  ('a1000000-0000-0000-0000-000000000003', 'What is a Foley catheter?', 'An indwelling urinary catheter inserted through the urethra into the bladder with an inflatable balloon to maintain position; provides continuous urine drainage and precise output measurement.', 'easy'),
  ('a1000000-0000-0000-0000-000000000003', 'What is the purpose of I&O monitoring?', 'Tracking all fluid intake (oral, IV, tube feeds) and output (urine, emesis, wound drainage, stool) to assess fluid balance, detect dehydration or overload, and guide clinical decision-making.', 'easy'),
  ('a1000000-0000-0000-0000-000000000003', 'What is normal capillary refill time?', 'Less than 2 seconds. Press the nail bed until it blanches (white), release, and count time to return to pink. CRT >2 seconds suggests poor peripheral perfusion.', 'easy'),
  ('a1000000-0000-0000-0000-000000000003', 'What are universal precautions?', 'Treating all blood and body fluids as if they are potentially infectious regardless of known diagnosis. Requires appropriate PPE (gloves, gown, mask, eye protection) whenever exposure risk exists.', 'easy'),
  ('a1000000-0000-0000-0000-000000000003', 'What is the 0-10 numeric pain rating scale?', 'A self-report scale where 0 = no pain and 10 = worst imaginable pain. Most commonly used adult pain assessment tool. Must be supplemented with behavioral assessment for non-verbal patients.', 'easy'),
  ('a1000000-0000-0000-0000-000000000003', 'What is the difference between a sign and a symptom?', 'A sign is an objective, measurable finding observed by a clinician (e.g., fever of 39°C, tachycardia). A symptom is a subjective experience reported by the patient (e.g., "I feel hot," "my chest hurts").', 'easy');
insert into public.cards (event_id, front, back, difficulty) values
  ('a1000000-0000-0000-0000-000000000003', 'Describe proper hand hygiene technique for handwashing with soap and water.', 'Wet hands under running water → apply soap → lather and rub all surfaces for ≥20 seconds (including between fingers, backs of hands, thumbs, and fingernails) → rinse thoroughly → dry with single-use paper towel → use towel to turn off faucet.', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'When should alcohol-based hand sanitizer NOT be used?', 'When hands are visibly soiled with dirt, blood, or body fluids. Also ineffective against Clostridioides difficile (C. diff) spores and norovirus — soap and water are required for these pathogens.', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'Describe the Sims'' position and when it is used.', 'Semi-prone position: patient lies on left side with right knee drawn up toward chest, left arm behind. Used for rectal examinations, enemas, suppository administration, and unconscious patients to promote airway drainage and prevent aspiration.', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'Describe the Trendelenburg position and its clinical uses.', 'Patient supine with the entire bed tilted so feet are higher than the head. Used for central line placement (internal jugular/subclavian), postural drainage of lung bases, and historically for shock (now controversial). Reverse Trendelenburg (head up) reduces aspiration risk.', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'What is the difference between clean technique and sterile technique?', 'Clean technique: reduces but does not eliminate microorganisms; used for non-invasive procedures (dressing changes on healing wounds, oral care, nasogastric tube insertion). Sterile technique: eliminates all microorganisms; required for invasive procedures entering sterile body cavities (urinary catheterization, surgical wounds, central line insertion, IV preparation).', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'What FiO2 does a nasal cannula deliver and at what flow rates?', 'Nasal cannula delivers 24–44% FiO2 at 1–6 L/min. Each 1 L/min increase raises FiO2 by approximately 4%. Comfortable for patients; allows eating and talking. Not appropriate when FiO2 >44% is needed.', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'What is a non-rebreather mask (NRB) and what FiO2 does it deliver?', 'An NRB is a face mask with a one-way valve and reservoir bag. The valve prevents exhaled air from re-entering the reservoir. Delivers 60–80% FiO2 at 10–15 L/min. Used for seriously ill patients requiring high-flow oxygen (CO poisoning, severe hypoxemia).', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'What is the Venturi mask and why is it used for COPD patients?', 'A precision oxygen delivery device using color-coded Venturi valves to deliver exact, controlled FiO2 (24–60%) at specific flow rates. Used for COPD patients who are "hypoxic CO2 retainers" — high FiO2 can blunt their hypoxic drive, causing respiratory depression; precise low-flow O2 is safer.', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'How is blood glucose monitoring performed and what are the normal ranges?', 'Obtain capillary blood sample (fingerstick with lancet), apply drop to test strip in glucometer. Normal fasting BG: 70–100 mg/dL. Pre-prandial target (DM): 80–130 mg/dL. Hypoglycemia: <70 mg/dL. Hyperglycemia: >180 mg/dL. Document result and assess for symptoms.', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'Describe the SBAR communication framework.', 'Situation: what is happening right now with the patient. Background: relevant clinical history, admitting diagnosis, current medications/labs. Assessment: your clinical impression of the problem. Recommendation: what action you need from the provider. Standardizes handoffs and urgent communications to reduce errors.', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'What is a SOAP note?', 'Subjective: patient''s own report (chief complaint, symptoms, HPI). Objective: measurable, observable data (vitals, physical exam, labs, imaging). Assessment: clinical interpretation and diagnosis. Plan: treatment plan, nursing interventions, follow-up. A systematic documentation framework used in clinical notes.', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'What is the Glasgow Coma Scale and how is it scored?', 'A neurological assessment tool scoring three responses: Eye opening (E1–4: none to spontaneous), Verbal response (V1–5: none to oriented), Motor response (M1–6: none to obeys commands). Maximum = 15 (normal consciousness). GCS ≤8 = severe brain injury; airway protection typically required.', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'What nursing interventions reduce fall risk?', 'Bed in lowest position with brakes locked, call light within reach, non-slip footwear, hourly rounding, fall-risk identifier (wristband/sign), bed alarm, clear path to bathroom, adequate lighting, medication review (sedatives, antihypertensives, diuretics), and patient/family education.', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'What is a nasogastric (NG) tube used for?', 'Gastric decompression (remove gas, fluid, or blood from the stomach), medication administration, enteral nutrition (tube feeding/gavage), and obtaining gastric specimens for analysis.', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'How is NG tube placement verified?', 'Gold standard: chest X-ray confirming tip position in stomach. Bedside: check aspirate pH (should be ≤5.5 for gastric placement). Auscultation of air insufflation is NOT reliable alone and is no longer recommended as the sole verification method.', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'What are the normal vital sign ranges for a 6-month-old infant?', 'HR: 80–140 bpm, RR: 25–40 breaths/min, BP: ~80/45 mmHg, Temperature: 36.5–37.5°C. Pediatric vital signs vary significantly by age; tachycardia is the earliest sign of distress and compensation in children.', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'What are the medication routes of administration and their characteristics?', 'Oral (PO): convenient, slow onset. Sublingual (SL): rapid absorption under tongue, bypasses first-pass. Buccal: absorbed through cheek mucosa. Topical: local effect on skin. Transdermal: systemic absorption through skin patch. Subcutaneous (SQ): slower absorption than IM. Intramuscular (IM): faster than SQ. Intravenous (IV): immediate, most precise.', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'What are the pressure ulcer (decubitus ulcer) stages?', 'Stage 1: Non-blanchable redness, skin intact. Stage 2: Partial-thickness skin loss, shallow open ulcer or intact/ruptured blister. Stage 3: Full-thickness loss, subcutaneous fat visible (no bone/tendon/muscle). Stage 4: Full-thickness, bone/tendon/muscle exposed. Unstageable: full-thickness, covered by eschar or slough.', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'What are the signs and symptoms of dehydration vs. fluid overload in nursing assessment?', 'Dehydration: dry mucous membranes, poor skin turgor, tachycardia, decreased urine output, hypotension, sunken eyes, concentrated urine (dark yellow). Fluid overload: peripheral edema, crackles (pulmonary edema), JVD, weight gain, hypertension, bounding pulse, S3 heart sound.', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'What is the nursing process (ADPIE)?', 'Assessment (systematic collection of patient data), Diagnosis (identify nursing problems based on data), Planning (establish SMART goals and interventions), Implementation (carry out the plan of care), Evaluation (assess whether goals were met and revise plan as needed). A cyclic, patient-centered framework.', 'medium'),
  ('a1000000-0000-0000-0000-000000000003', 'What pain assessment scale is used for non-verbal patients?', 'The CPOT (Critical-Care Pain Observation Tool) or FLACC scale (Face, Legs, Activity, Cry, Consolability). FLACC rates each domain 0–2 for a total score of 0–10. Used for infants, toddlers, intubated patients, and cognitively impaired adults who cannot self-report pain.', 'medium');
insert into public.cards (event_id, front, back, difficulty) values
  ('a1000000-0000-0000-0000-000000000003', 'Calculate: Order is amoxicillin 875 mg PO; available is amoxicillin 250 mg/5 mL suspension. How many mL to administer?', 'D/H × V = 875 mg ÷ 250 mg × 5 mL = 3.5 × 5 mL = 17.5 mL. Always round to appropriate decimal for the measurement device available.', 'hard'),
  ('a1000000-0000-0000-0000-000000000003', 'Calculate IV drip rate: 1,000 mL NS to infuse over 8 hours with a drop factor of 15 gtt/mL.', '(Volume × Drop Factor) ÷ Time in minutes = (1000 × 15) ÷ (8 × 60) = 15,000 ÷ 480 = 31.25 ≈ 31 gtt/min.', 'hard'),
  ('a1000000-0000-0000-0000-000000000003', 'Explain proper subcutaneous insulin injection technique.', 'Use a short, fine-gauge needle (4–6 mm). Cleanse site with alcohol. Pinch 1 inch of subcutaneous tissue. Insert at 45–90° depending on body habitus. Inject slowly. Do NOT aspirate for insulin. Apply gentle pressure — do not rub (alters absorption). Rotate sites within the same anatomical region (e.g., abdomen) for consistent absorption.', 'hard'),
  ('a1000000-0000-0000-0000-000000000003', 'What are the signs and management of digoxin toxicity?', 'Therapeutic range: 0.5–2.0 ng/mL. Early toxicity: anorexia, nausea, vomiting, fatigue. Cardiac: bradycardia, AV block, ventricular arrhythmias. Visual: halos around lights, yellow-green tint to vision. Hypokalemia dramatically potentiates toxicity. Management: hold digoxin, correct electrolytes, Digibind (digoxin-specific Fab fragments) for severe toxicity.', 'hard'),
  ('a1000000-0000-0000-0000-000000000003', 'Describe the nurse''s management of a patient experiencing anaphylaxis.', 'Immediately: Epinephrine 0.3–0.5 mg IM (anterolateral thigh, auto-injector or 1:1000 concentration) — first-line, life-saving. Call for emergency response. Position patient supine with legs elevated (unless dyspnea). O2 via NRB. IV access + fluid bolus (hypovolemia from vasodilation). Diphenhydramine and corticosteroids (adjuncts). Prepare for airway management. Monitor continuously.', 'hard'),
  ('a1000000-0000-0000-0000-000000000003', 'What are the components of a comprehensive pain assessment using OLDCART?', 'Onset: when did the pain start and was it sudden or gradual? Location: where exactly? Does it radiate? Duration: how long does it last? Characteristics: quality — sharp, dull, throbbing, burning? Aggravating factors: what makes it worse? Relieving factors: what makes it better? Treatment: what has the patient tried and did it help?', 'hard'),
  ('a1000000-0000-0000-0000-000000000003', 'Describe care of a central venous catheter (CVC) to prevent CLABSI.', 'Central Line-Associated Bloodstream Infection (CLABSI) bundle: Strict hand hygiene. Maximal sterile barrier during insertion. Chlorhexidine skin antisepsis. Avoid femoral site. Daily review of necessity and prompt removal. Scrub-the-hub before accessing. Transparent, occlusive dressing; change every 7 days or when soiled/loose. Assess insertion site daily for signs of infection.', 'hard'),
  ('a1000000-0000-0000-0000-000000000003', 'What nursing assessments are required before and during heparin therapy?', 'Before: baseline aPTT, PT, platelet count, assess for bleeding risk/contraindications. During: monitor aPTT (therapeutic: 60–100 sec, or 1.5–2.5× normal), observe for bleeding (hematuria, melena, unusual bruising, prolonged oozing from sites), monitor platelet count for HIT (heparin-induced thrombocytopenia; drop >50% on day 4–10). Antidote: protamine sulfate.', 'hard'),
  ('a1000000-0000-0000-0000-000000000003', 'Describe the VAP prevention bundle for ventilated patients.', 'Ventilator-Associated Pneumonia (VAP) bundle: (1) Head of bed elevation 30–45°. (2) Daily sedation vacation and spontaneous breathing trial. (3) Oral care with chlorhexidine gluconate every 2 hours. (4) Subglottic secretion suctioning. (5) Peptic ulcer prophylaxis (PPI/H2 blocker). (6) DVT prophylaxis. (7) Hand hygiene before every contact.', 'hard'),
  ('a1000000-0000-0000-0000-000000000003', 'What are the steps and monitoring requirements for a blood transfusion?', 'Verify physician order. Obtain informed consent. Two-nurse verification: ABO/Rh type, unit number, expiration, patient ID. Prime tubing with 0.9% NaCl only. Baseline vitals. Infuse slowly for first 15 minutes (detect transfusion reaction). Vitals at 15 min, then per facility protocol. Infuse each unit within 4 hours. Watch for reaction: fever, chills, flank pain, hypotension, hemoglobinuria (stop immediately if suspected).', 'hard'),
  ('a1000000-0000-0000-0000-000000000003', 'What is the nurse''s role in the informed consent process?', 'The nurse is a WITNESS to the patient''s signature — NOT responsible for obtaining consent (that is the physician''s legal duty). The nurse must: confirm the patient understands the procedure, risks, benefits, and alternatives; verify the patient is competent and not coerced; ensure questions are answered. If the patient has doubts, the nurse must notify the physician before proceeding.', 'hard'),
  ('a1000000-0000-0000-0000-000000000003', 'What are the nursing responsibilities for post-operative care in the PACU?', 'Assess airway patency and respiratory effort, monitor vitals every 5–15 minutes initially, assess level of consciousness (modified Aldrete score), manage pain and PONV, monitor surgical site for bleeding, maintain IV access, assess urinary output, ensure patient meets discharge criteria (Aldrete score ≥8-9, stable vitals, adequate analgesia) before transfer to floor.', 'hard'),
  ('a1000000-0000-0000-0000-000000000003', 'What is the difference between SIADH and diabetes insipidus in terms of nursing management?', 'SIADH: excess ADH → water retention → hyponatremia, concentrated urine. Nursing: fluid restriction (800–1000 mL/day), monitor Na+, hypertonic saline for severe cases, neurological checks. DI: deficient ADH (or resistance) → massive dilute urine output (3–20 L/day) → hypernatremia, dehydration. Nursing: replace fluids, administer desmopressin (DDAVP), monitor urine specific gravity and electrolytes.', 'hard'),
  ('a1000000-0000-0000-0000-000000000003', 'Describe the assessment and management of post-operative ileus.', 'Assessment: absent or hypoactive bowel sounds, abdominal distension, inability to pass flatus or stool, nausea/vomiting, absence of hunger. Management: early ambulation (most effective intervention), minimize opioid use (alvimopan may help), IV fluid maintenance, NPO with NG decompression if severe distension, advance diet slowly (clear liquids → solids) when bowel sounds return and flatus is passed.', 'hard'),
  ('a1000000-0000-0000-0000-000000000003', 'What are the nursing interventions for a patient in sinus bradycardia with hemodynamic instability?', 'Position patient supine/Trendelenburg, establish IV access, apply O2, attach cardiac monitor. Prepare atropine 0.5 mg IV push (first-line; may repeat every 3–5 min to max 3 mg). If atropine ineffective: transcutaneous pacing or dopamine/epinephrine infusion. Identify and treat underlying cause (vagal stimulation, beta-blocker toxicity, hypothyroidism, inferior MI). Prepare for transvenous pacemaker if needed.', 'hard');
insert into public.cards (event_id, front, back, difficulty) values
  ('a1000000-0000-0000-0000-000000000004', 'What are the three stages of prenatal development?', 'Germinal (fertilization to 2 weeks), Embryonic (weeks 3–8), and Fetal (week 9 through birth). Each stage has unique characteristics and vulnerabilities.', 'easy'),
  ('a1000000-0000-0000-0000-000000000004', 'What occurs during the germinal stage of prenatal development?', 'Fertilization forms a zygote → rapid mitotic division (cleavage) → morula → blastocyst → implantation in the uterine wall (~day 6–10). The inner cell mass forms the embryo; the outer layer forms the placenta.', 'easy'),
  ('a1000000-0000-0000-0000-000000000004', 'What is the embryonic stage?', 'Weeks 3–8 of prenatal development; all major organ systems begin to form (organogenesis); the embryo is most vulnerable to teratogens; the embryo develops from a flat disc into a recognizable human form.', 'easy'),
  ('a1000000-0000-0000-0000-000000000004', 'What is the fetal stage?', 'Week 9 through birth; characterized by rapid growth, refinement of organ systems, and increasing complexity. The fetus reaches viability (survivability outside the womb) around 22–24 weeks gestation.', 'easy'),
  ('a1000000-0000-0000-0000-000000000004', 'What is object permanence and when does it develop?', 'The understanding that objects continue to exist even when they cannot be seen, heard, or touched. Develops around 8–12 months, marking the end of Piaget''s early sensorimotor stage.', 'easy'),
  ('a1000000-0000-0000-0000-000000000004', 'What are the five levels of Maslow''s Hierarchy of Needs?', 'From base to peak: (1) Physiological (food, water, sleep, warmth), (2) Safety (security, stability), (3) Love and Belonging (relationships, intimacy), (4) Esteem (self-worth, achievement), (5) Self-Actualization (fulfilling potential).', 'easy'),
  ('a1000000-0000-0000-0000-000000000004', 'What are the five stages of Kübler-Ross''s grief model?', 'Denial, Anger, Bargaining, Depression, Acceptance. These stages are non-linear; individuals may move between them or not experience all stages. Applies to grief, terminal illness, and significant loss.', 'easy'),
  ('a1000000-0000-0000-0000-000000000004', 'What is puberty?', 'The biological process of sexual maturation involving hormonal changes, growth spurts, and development of secondary sex characteristics. Typically begins ages 10–14 in females (estrogen/progesterone) and 12–16 in males (testosterone).', 'easy'),
  ('a1000000-0000-0000-0000-000000000004', 'What is the Moro reflex?', 'A primitive reflex in newborns: sudden loud noise or change in position causes the infant to extend arms outward, open hands, then bring arms back toward midline in a hugging motion. Disappears by 3–4 months; persistence beyond 6 months may indicate neurological dysfunction.', 'easy'),
  ('a1000000-0000-0000-0000-000000000004', 'What is the rooting reflex?', 'When the corner of the infant''s mouth or cheek is touched, the head turns toward the stimulus and sucking movements begin. Helps the infant locate the nipple for feeding. Present from birth; disappears at 3–4 months.', 'easy'),
  ('a1000000-0000-0000-0000-000000000004', 'What is the difference between gross motor and fine motor development?', 'Gross motor: uses large muscle groups for major movements — rolling, sitting, crawling, walking, running. Fine motor: uses small muscles for precise manipulation — grasping, pincer grip, writing, using utensils.', 'easy'),
  ('a1000000-0000-0000-0000-000000000004', 'What is the difference between growth and development?', 'Growth: quantitative, measurable physical changes (increase in height, weight, organ size). Development: qualitative changes in function, complexity, and organization (motor skill acquisition, language, social-emotional maturity).', 'easy'),
  ('a1000000-0000-0000-0000-000000000004', 'What is Piaget''s sensorimotor stage?', 'Birth to ~2 years. Infants learn through sensory experience and motor activity. Key achievements: object permanence, beginning of symbolic thought, intentional behavior. Divided into 6 sub-stages.', 'easy'),
  ('a1000000-0000-0000-0000-000000000004', 'What is Piaget''s formal operational stage?', 'Ages ~12 and older. Ability for abstract reasoning, hypothetical thinking ("what if..."), deductive logic, and metacognition (thinking about one''s own thinking). Not all adults consistently reach this stage.', 'easy'),
  ('a1000000-0000-0000-0000-000000000004', 'What is Erikson''s first psychosocial stage?', 'Trust vs. Mistrust (birth to ~18 months). Infants learn to trust caregivers based on consistency and responsiveness. Virtue: Hope. Failure to resolve leads to fear, insecurity, and mistrust of the world.', 'easy');
insert into public.cards (event_id, front, back, difficulty) values
  ('a1000000-0000-0000-0000-000000000004', 'Describe all 8 of Erikson''s psychosocial stages with age ranges and virtues.', '1. Trust vs. Mistrust (0–18 mo): Hope. 2. Autonomy vs. Shame (18 mo–3 yr): Will. 3. Initiative vs. Guilt (3–6 yr): Purpose. 4. Industry vs. Inferiority (6–12 yr): Competence. 5. Identity vs. Role Confusion (12–18 yr): Fidelity. 6. Intimacy vs. Isolation (young adult): Love. 7. Generativity vs. Stagnation (middle adult): Care. 8. Ego Integrity vs. Despair (older adult): Wisdom.', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'Describe Piaget''s preoperational stage.', 'Ages 2–7. Symbolic thinking develops (language, pretend play). Key limitations: egocentrism (cannot take another''s perspective — demonstrated by the Three Mountains Task), centration (focus on one aspect of a situation), animism (inanimate objects have feelings), and lack of conservation (can''t understand that quantity is constant despite changes in appearance).', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'Describe Piaget''s concrete operational stage.', 'Ages 7–11. Children develop logical thinking about concrete (real, tangible) objects. Key achievements: conservation (quantity unchanged despite appearance), classification (grouping by attributes), seriation (ordering by size), and reversibility (mental actions can be reversed). Cannot yet reason about purely abstract concepts.', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'What is Vygotsky''s Zone of Proximal Development (ZPD)?', 'The distance between what a learner can accomplish independently and what they can accomplish with guidance from a more capable other (teacher, peer). The ZPD represents the optimal challenge zone for learning. Clinical application: health educators should target teaching at a patient''s ZPD.', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'Describe infant developmental milestones at 4, 8, and 12 months.', '4 months: holds head steady, social smile, coos, tracks objects, reaches for things. 8 months: sits without support, begins crawling, babbles (ma-ma, da-da), stranger anxiety, transfers objects between hands. 12 months: pulls to stand, may take first steps, 1–2 meaningful words, waves bye-bye, object permanence established, separation anxiety.', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'What are the major developmental characteristics of toddlers (ages 1–3 years)?', 'Motor: walks alone by 15 months, climbs stairs, runs by age 2, uses utensils. Language: 50-word vocabulary by age 2, 2-word phrases by 24 months, 3-word sentences by 36 months. Social: parallel play (plays alongside but not with others), negativism ("No!"), autonomy-seeking, toilet training (typically 2–3 years), temper tantrums.', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'What is Bowlby''s attachment theory?', 'John Bowlby proposed that infants have an innate biological drive to seek proximity to caregivers for protection and survival. The quality of this early attachment relationship forms an "internal working model" that shapes emotional regulation, self-concept, and relationship patterns throughout life.', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'What are Ainsworth''s four attachment styles from the Strange Situation?', 'Secure (most common, ~65%): uses caregiver as safe base; distressed at separation, easily comforted at reunion. Anxious-Avoidant (~20%): little distress at separation, ignores caregiver at reunion. Anxious-Ambivalent/Resistant (~15%): intense distress, difficult to comfort, angry at reunion. Disorganized (~5%): no consistent strategy; associated with trauma/abuse.', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'What is a teratogen and give four examples?', 'Any agent that can disrupt normal prenatal development and cause structural or functional birth defects. Examples: (1) Alcohol → fetal alcohol syndrome (FAS); (2) Thalidomide → limb reduction defects; (3) Rubella virus → congenital rubella syndrome (heart defects, cataracts, deafness); (4) Isotretinoin (Accutane) → craniofacial/cardiac malformations. Most dangerous during embryonic stage (weeks 3–8).', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'Describe Kohlberg''s three levels of moral development.', 'Pre-conventional (childhood): morality based on consequences. Stage 1: avoid punishment. Stage 2: seek reward. Conventional (adolescence/most adults): morality based on social rules. Stage 3: please others/maintain relationships. Stage 4: law and order. Post-conventional (few adults): morality based on universal principles. Stage 5: social contract. Stage 6: universal ethical principles.', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'Describe physical changes of female puberty in sequence.', 'Breast development (thelarche) → pubic hair (pubarche) → axillary hair → growth spurt (peak around age 12) → widening of hips → onset of menstruation (menarche, average age 12.5 in the US). Driven by estrogen from the ovaries and androgens from the adrenal glands.', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'Describe physical and cognitive changes in early adulthood (20s–30s).', 'Physical: peak of muscle mass, bone density, cardiovascular efficiency, sensory acuity, and immune function. Reproductive capacity at maximum. Cognitive: formal operational thinking established; postformal thought may develop (recognizing that problems can have multiple solutions depending on context). Lifestyle choices during this period establish long-term health trajectories.', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'What are the principles of cephalocaudal and proximodistal development?', 'Cephalocaudal: development proceeds from head to toe (infants control head/neck before trunk, trunk before legs). Proximodistal: development proceeds from the central body outward (spinal cord matures before limbs; shoulder control precedes wrist/hand control). Both principles reflect the orderly, predictable sequence of motor development.', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'What is theory of mind and when does it develop?', 'The ability to understand that other people have mental states (beliefs, desires, intentions) that are different from one''s own and from reality. Typically develops around ages 3–5; assessed with false-belief tasks. Impaired in autism spectrum disorder. Essential for empathy, deception, and social communication.', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'What is the normal aging process of the musculoskeletal system (senescence)?', 'Progressive sarcopenia (muscle mass loss) beginning in the 30s. Bone density decreases after age 35 (accelerated after menopause in women) → osteopenia → osteoporosis. Intervertebral disc degeneration → height loss. Joint stiffness from cartilage thinning. Slowed reaction time. Increased fracture risk (especially hip, spine, wrist). Prevention: weight-bearing exercise, calcium, vitamin D.', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'Describe the infant Babinski and palmar grasp reflexes.', 'Babinski reflex: stroke the lateral sole from heel to toe → toes fan out (positive Babinski). Normal in infants <2 years; abnormal (indicates corticospinal tract lesion) in adults. Palmar grasp reflex: place finger in infant''s palm → fingers curl and grip. Present from birth; disappears by 3–6 months as voluntary grasping develops.', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'What are developmental characteristics of school-age children (6–12 years)?', 'Erikson Stage 4: Industry vs. Inferiority. Children master academic and social skills; compare themselves to peers. Piaget: concrete operational stage — logical thinking, conservation, classification. Language: complex sentences, reading, writing. Social: cooperative play, peer relationships become central, moral reasoning develops. Physical: steady growth, fine motor skills refined.', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'Describe cognitive changes in late adulthood (65+ years).', 'Fluid intelligence (processing speed, working memory, problem-solving) declines; crystallized intelligence (accumulated knowledge, vocabulary, wisdom) remains stable or increases. Normal: slower recall, longer reaction time. Pathological: dementia (progressive memory loss interfering with daily function). Depression is often underdiagnosed and mistaken for dementia ("pseudodementia").', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'What is scaffolding in Vygotsky''s theory?', 'Temporary instructional support provided by a more knowledgeable other to help a learner accomplish a task within their ZPD. Support is gradually withdrawn (faded) as the learner internalizes the skill and becomes more independent. Examples: guided practice, hints, worked examples, prompting.', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'Describe adolescent development (ages 12–18) across domains.', 'Physical: puberty completion, peak growth velocity, brain continues developing (prefrontal cortex not mature until ~25). Cognitive: formal operational thinking, abstract reasoning, risk-taking. Social-emotional: identity formation (Erikson Stage 5), peer group importance, individuation from parents, development of autonomy and intimate friendships. Moral: conventional to post-conventional reasoning.', 'medium'),
  ('a1000000-0000-0000-0000-000000000004', 'What are Kübler-Ross''s stages and how do they apply to nursing care of dying patients?', 'Denial → Anger → Bargaining → Depression → Acceptance. Nursing application: meet patients where they are emotionally; do not try to rush through stages. In Denial: provide honest information gently. In Anger: don''t take it personally; listen. In Bargaining: listen without judgment. In Depression: provide presence and support. In Acceptance: facilitate comfort and closure. Not all patients reach acceptance.', 'medium');
insert into public.cards (event_id, front, back, difficulty) values
  ('a1000000-0000-0000-0000-000000000004', 'What is fetal alcohol syndrome (FAS) and what causes it?', 'FAS is a permanent condition caused by prenatal alcohol exposure at any point during gestation (no safe level). Features: characteristic facial dysmorphology (smooth philtrum, thin upper lip, small palpebral fissures), growth restriction, and CNS abnormalities (intellectual disability, learning difficulties, behavioral problems). Alcohol is the most common preventable cause of intellectual disability.', 'hard'),
  ('a1000000-0000-0000-0000-000000000004', 'Compare and contrast Piaget''s and Vygotsky''s theories of cognitive development.', 'Piaget: development precedes learning; universal, biologically-driven stages; child as solo discoverer constructing knowledge through interaction with environment. Vygotsky: learning drives development; social interaction and cultural tools are central; language is the primary tool of thought. Piaget neglects social context; Vygotsky neglects biological maturation. Both inform effective health education.', 'hard'),
  ('a1000000-0000-0000-0000-000000000004', 'Explain the neurological basis of adolescent risk-taking behavior.', 'The limbic system (emotional response, reward sensitivity — dopaminergic) matures before the prefrontal cortex (impulse control, judgment, planning). This asynchronous neurodevelopment (prefrontal cortex not fully mature until age ~25) creates a window of heightened emotionality, sensation-seeking, susceptibility to peer influence, and impulsivity. Has implications for injury prevention and health risk education.', 'hard'),
  ('a1000000-0000-0000-0000-000000000004', 'What is the Strange Situation experiment and what did it demonstrate?', 'Mary Ainsworth''s controlled laboratory procedure (1970s): mother and infant (12–18 months) experience brief separations and reunions in a novel environment with a stranger. Used to classify attachment security based on the infant''s stress response (separation) and behavior upon reunion. Demonstrated that maternal sensitivity and responsiveness during the first year predicts attachment security and later social-emotional outcomes.', 'hard'),
  ('a1000000-0000-0000-0000-000000000004', 'What are adverse childhood experiences (ACEs) and their long-term health consequences?', 'ACEs (Felitti et al., 1998 CDC-Kaiser study): abuse, neglect, and household dysfunction experienced before age 18. Dose-response relationship: more ACEs = worse outcomes. Adults with 4+ ACEs have 2–4× higher risk of heart disease, stroke, diabetes, cancer, depression, suicide, and substance abuse. Mechanism: toxic stress disrupts HPA axis, neurological development, and immune function. Trauma-informed care is essential.', 'hard'),
  ('a1000000-0000-0000-0000-000000000004', 'Describe Bronfenbrenner''s ecological systems theory.', 'Human development occurs within nested, interacting environmental systems: Microsystem (immediate environment: family, school, peers). Mesosystem (interactions between microsystems: parent-teacher relationship). Exosystem (settings that indirectly affect the child: parent''s workplace, community services). Macrosystem (cultural values, laws, economics). Chronosystem (changes over time in the person or environment). Development is bidirectional.', 'hard'),
  ('a1000000-0000-0000-0000-000000000004', 'What is the critical period concept and give a clinical example.', 'A biologically determined, time-limited window during which specific environmental experiences must occur for normal development; if the experience is absent during this window, normal development may be permanently compromised. Clinical example: congenital cataracts — if not corrected before age 3–5, the visual cortex fails to develop normal binocular vision (amblyopia). Language acquisition has a critical period ending around puberty.', 'hard'),
  ('a1000000-0000-0000-0000-000000000004', 'Describe postformal thought and its development in adulthood.', 'Postformal thought extends beyond Piaget''s formal operations to recognize that: (1) problems often have multiple valid solutions depending on context (relativistic thinking), (2) contradictions can coexist (dialectical thinking), (3) emotion and practical experience inform reasoning alongside pure logic. Emerges in young adulthood through experience and is relevant to clinical decision-making and ethical reasoning.', 'hard'),
  ('a1000000-0000-0000-0000-000000000004', 'What is emerging adulthood (Arnett) and how does it differ from traditional adulthood?', 'A developmental stage proposed by Jeffrey Arnett for ages 18–25 in industrialized societies. Characterized by: identity exploration (especially in love and work), instability, self-focus, feeling "in between" adolescence and adulthood, and a sense of endless possibilities. Unlike previous generations, emerging adults delay marriage, parenthood, and career commitment while pursuing education. Not universal — more applicable to western, affluent societies.', 'hard'),
  ('a1000000-0000-0000-0000-000000000004', 'Describe the difference between fluid and crystallized intelligence and aging.', 'Fluid intelligence (Horn-Cattell): the ability to reason, solve novel problems, and process information quickly; peaks in young adulthood (~20s) and declines progressively with age (processing speed, working memory). Crystallized intelligence: accumulated knowledge, verbal ability, and experiential wisdom built over a lifetime; remains stable or continues to grow into late adulthood. Explains why older adults excel in knowledge-based domains but struggle with timed novel tasks.', 'hard'),
  ('a1000000-0000-0000-0000-000000000004', 'How does cultural context influence developmental norms and healthcare?', 'Developmental norms (milestone timing, sleep practices, independence training) are largely based on Western, educated, industrialized, rich, democratic (WEIRD) populations. Culture shapes when and how milestones are expressed: e.g., co-sleeping infants may walk later but show other competencies; language milestone norms vary by bilingual exposure. Clinicians must apply culturally sensitive, non-ethnocentric assessment to avoid misdiagnosis of developmental delay.', 'hard'),
  ('a1000000-0000-0000-0000-000000000004', 'Describe the terminal process of active dying and nursing palliative care.', 'Signs of active dying (hours to days): mottled/discolored extremities, Cheyne-Stokes respirations (irregular breathing with apnea), unresponsiveness, peripheral cooling, death rattle (retained secretions). Nursing priorities: pain and symptom control (opioids for dyspnea/pain, glycopyrrolate for secretions), repositioning, mouth care, silence of unnecessary monitoring. Family support: presence, anticipatory guidance, spiritual care. Hospice philosophy: comfort and dignity over curative treatment.', 'hard'),
  ('a1000000-0000-0000-0000-000000000004', 'What is senescence and its impact on pharmacokinetics in older adults?', 'Senescence is the gradual biological aging process affecting all body systems. Pharmacokinetic changes: Absorption (slowed GI motility — slower drug onset). Distribution (↓total body water → higher concentrations of water-soluble drugs; ↑fat stores → prolonged effect of fat-soluble drugs). Metabolism (↓hepatic blood flow and enzyme activity → slower first-pass metabolism). Excretion (↓GFR → reduced renal clearance → drug accumulation). Polypharmacy and falls risk are major concerns.', 'hard'),
  ('a1000000-0000-0000-0000-000000000004', 'Describe the psychosocial development of middle adulthood (40s–60s) per Erikson and the physical changes.', 'Erikson Stage 7: Generativity vs. Stagnation. The task is contributing to the next generation through parenting, mentoring, creating, and community leadership. Virtue: Care. Stagnation leads to self-absorption and meaninglessness. Physical: presbyopia (vision), presbycusis (hearing), menopause in women (estrogen loss → hot flashes, osteoporosis risk), declining testosterone in men, increased chronic disease risk, and continued cognitive efficiency in crystallized domains.', 'hard'),
  ('a1000000-0000-0000-0000-000000000004', 'What is the difference between normal memory changes in aging and pathological dementia?', 'Normal aging: slower recall, occasional word-finding difficulty, takes longer to learn new skills — BUT the information is ultimately retrievable; daily function is preserved. Dementia (pathological): progressive, irreversible loss of memory and cognitive function interfering with ADLs; disorientation, personality changes, language breakdown. Alzheimer''s disease (most common): characterized by amyloid plaques and neurofibrillary tangles in the hippocampus and cortex.', 'hard');
insert into public.cards (event_id, front, back, difficulty) values
  ('a1000000-0000-0000-0000-000000000005', 'What are the three macronutrients?', 'Carbohydrates, proteins, and fats (lipids). These provide the body with energy and the building blocks for growth, repair, and physiological function.', 'easy'),
  ('a1000000-0000-0000-0000-000000000005', 'How many calories does each macronutrient provide per gram?', 'Carbohydrates: 4 kcal/g. Protein: 4 kcal/g. Fat: 9 kcal/g. Alcohol is not a macronutrient but provides 7 kcal/g.', 'easy'),
  ('a1000000-0000-0000-0000-000000000005', 'What is the primary function of carbohydrates?', 'To provide energy; glucose is the preferred fuel for the brain (which requires ~120 g/day) and red blood cells. Carbohydrates are stored as glycogen in the liver and muscle for rapid mobilization.', 'easy'),
  ('a1000000-0000-0000-0000-000000000005', 'What are the fat-soluble vitamins?', 'Vitamins A, D, E, and K (mnemonic: ADEK). Absorbed with dietary fat; stored in adipose tissue and liver; excess accumulation can cause toxicity (especially A and D).', 'easy'),
  ('a1000000-0000-0000-0000-000000000005', 'What are the water-soluble vitamins?', 'Vitamin C (ascorbic acid) and the 8 B vitamins (B1/thiamine, B2/riboflavin, B3/niacin, B5/pantothenic acid, B6/pyridoxine, B7/biotin, B9/folate, B12/cobalamin). Not stored; excess excreted in urine; must be replenished regularly.', 'easy'),
  ('a1000000-0000-0000-0000-000000000005', 'What disease is caused by vitamin C deficiency?', 'Scurvy. Vitamin C is essential for collagen synthesis. Deficiency leads to: bleeding gums, perifollicular hemorrhages, impaired wound healing, corkscrew hairs, fatigue, and joint pain. Historically afflicted sailors on long voyages.', 'easy'),
  ('a1000000-0000-0000-0000-000000000005', 'What disease is caused by vitamin D deficiency in children and adults?', 'Children: Rickets (soft, weakened, and deformed bones — bowing of legs, enlarged joints). Adults: Osteomalacia (bone softening, bone pain, muscle weakness). Both result from impaired calcium and phosphorus absorption for bone mineralization.', 'easy'),
  ('a1000000-0000-0000-0000-000000000005', 'What is iron''s primary role in the body?', 'Iron is an essential component of hemoglobin (oxygen transport in red blood cells) and myoglobin (oxygen storage in muscle). Also required for cytochromes in electron transport chain and immune function.', 'easy'),
  ('a1000000-0000-0000-0000-000000000005', 'What is iron deficiency anemia?', 'The most common nutritional deficiency worldwide; insufficient iron for hemoglobin synthesis → microcytic, hypochromic anemia. Symptoms: fatigue, pallor, dyspnea on exertion, pica (craving non-food items), koilonychia (spoon-shaped nails), decreased exercise tolerance.', 'easy'),
  ('a1000000-0000-0000-0000-000000000005', 'What does the USDA MyPlate recommend?', 'Half the plate: fruits and vegetables (variety). Quarter: whole grains. Quarter: lean protein. Dairy on the side. Emphasizes variety, balance, adequate fiber, and limiting added sugars, saturated fat, trans fat, and sodium.', 'easy'),
  ('a1000000-0000-0000-0000-000000000005', 'What are the 9 essential amino acids?', 'Histidine, Isoleucine, Leucine, Lysine, Methionine, Phenylalanine, Threonine, Tryptophan, Valine. Mnemonic: "His Ile Leu Lys Met Phe Thr Trp Val." Cannot be synthesized by the body; must come from diet.', 'easy'),
  ('a1000000-0000-0000-0000-000000000005', 'What is the difference between saturated and unsaturated fats?', 'Saturated: no double bonds in carbon chain; solid at room temperature (butter, lard, coconut oil); raises LDL cholesterol. Unsaturated: one (mono) or more (poly) double bonds; liquid at room temperature; includes heart-healthy omega-3s and omega-6s.', 'easy'),
  ('a1000000-0000-0000-0000-000000000005', 'What is dietary fiber and its two types?', 'Indigestible plant carbohydrate. Soluble fiber (oats, legumes, apples): dissolves in water, forms gel → lowers LDL cholesterol and slows glucose absorption. Insoluble fiber (wheat bran, vegetables): adds bulk → promotes bowel regularity and prevents constipation.', 'easy'),
  ('a1000000-0000-0000-0000-000000000005', 'What is BMI and the standard classifications?', 'Body Mass Index = weight (kg) ÷ height (m)². Underweight: <18.5. Normal: 18.5–24.9. Overweight: 25.0–29.9. Obese Class I: 30.0–34.9. Obese Class II: 35.0–39.9. Obese Class III (severe): ≥40. Limitations: does not distinguish fat from muscle or assess fat distribution.', 'easy'),
  ('a1000000-0000-0000-0000-000000000005', 'What is calcium''s role in the body?', 'Essential for bone and teeth mineralization (99% of body calcium is in bone), muscle contraction (including cardiac muscle), nerve impulse transmission, blood clotting (coagulation factor activation), and enzyme function. Deficiency: hypocalcemia → tetany, osteoporosis.', 'easy');
insert into public.cards (event_id, front, back, difficulty) values
  ('a1000000-0000-0000-0000-000000000005', 'What are the functions and deficiency diseases of vitamin A?', 'Functions: vision (retinal is a component of rhodopsin for night vision), immune function, cell differentiation, reproduction, and fetal development. Deficiency: night blindness (earliest sign), xerophthalmia (dry eyes → blindness), increased susceptibility to infection. Excess (toxicity): teratogenic, liver damage, increased intracranial pressure.', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'What is vitamin B12 (cobalamin) and its clinical importance?', 'Essential for: DNA synthesis, red blood cell maturation, and myelin synthesis. Deficiency causes: megaloblastic anemia (large, immature RBCs) AND subacute combined degeneration of the spinal cord (posterior and lateral columns). Risk groups: vegans, elderly (decreased intrinsic factor), pernicious anemia patients. Parenteral B12 required when intrinsic factor is absent.', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'Why is folic acid (vitamin B9) critical during early pregnancy?', 'Folic acid is essential for DNA synthesis and cell division. Deficiency during the first 28 days post-conception (often before pregnancy is known) causes failure of neural tube closure → Neural Tube Defects: spina bifida (incomplete closure of the spinal cord) and anencephaly (absence of major brain portions). Recommended: 400–800 mcg/day for all women of childbearing age.', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'What is the glycemic index (GI) and its clinical relevance?', 'GI measures how rapidly a food''s carbohydrates raise blood glucose compared to pure glucose (reference = 100). Low GI (<55): gradual rise (legumes, most fruits, oatmeal). Medium GI (56–69). High GI (>70): rapid spikes (white bread, white rice, potatoes). Low-GI diets improve postprandial glycemic control in type 2 diabetes and reduce insulin demand.', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'What is the difference between HDL and LDL cholesterol?', 'LDL ("bad" cholesterol): carries cholesterol from liver to peripheral tissues; excess deposits in arterial walls → atherosclerosis. Goal: <100 mg/dL (high-risk patients <70 mg/dL). HDL ("good" cholesterol): reverse cholesterol transport — carries cholesterol from tissues back to liver for excretion; protective. Goal: >60 mg/dL. Both are components of total cholesterol.', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'What are omega-3 fatty acids and their health benefits?', 'Polyunsaturated fatty acids: EPA and DHA (from fatty fish — salmon, mackerel, sardines) and ALA (from flaxseed, walnuts). Benefits: anti-inflammatory, reduce triglycerides, modestly reduce BP, reduce cardiovascular event risk, support fetal brain and eye development (DHA), may reduce depression. ALA must be converted to EPA/DHA (inefficient conversion in humans).', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'What is basal metabolic rate (BMR) and what factors affect it?', 'BMR is the minimum energy required to maintain vital physiological functions at complete rest (breathing, circulation, thermoregulation, organ function). Accounts for ~60–75% of total daily energy expenditure. Increases with: greater lean body mass, male sex, younger age, hyperthyroidism, fever (BMR increases ~7% per degree Fahrenheit). Decreases with: aging, reduced lean mass, hypothyroidism, caloric restriction.', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'What is the thermic effect of food (TEF)?', 'The energy required to digest, absorb, and metabolize food; approximately 10% of total daily caloric intake. Protein has the highest TEF (20–30% of protein calories); carbohydrates: 5–10%; fat: 0–3%. High-protein diets slightly increase energy expenditure, which may contribute to weight management.', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'Describe the DASH diet.', 'Dietary Approaches to Stop Hypertension: rich in fruits, vegetables, low-fat dairy, whole grains, and lean protein; limits sodium (<2,300 mg/day; ideal <1,500 mg/day for hypertensives), saturated fat, and added sugars. Clinical evidence: reduces systolic BP by 8–14 mmHg, comparable to single antihypertensive medication. Also reduces LDL and reduces cardiovascular risk.', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'Describe the Mediterranean diet and its health outcomes.', 'Rich in olive oil (primary fat), fruits, vegetables, legumes, nuts, whole grains, and fish; moderate wine with meals; limited red meat and processed foods. Health benefits (strong evidence): reduced cardiovascular disease (Lyon Heart Study: 70% reduction in events), reduced type 2 diabetes risk, lower all-cause mortality, possible neuroprotective effects.', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'What is a renal diet and why is it prescribed?', 'For chronic kidney disease patients: restricts protein (reduces uremic waste — BUN), potassium (prevents hyperkalemia → cardiac arrhythmias), phosphorus (prevents renal osteodystrophy and vascular calcification), sodium (BP control and fluid management), and often fluid intake. As CKD progresses, restrictions become more stringent. Dietitian consultation is essential.', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'What are the nutritional needs during pregnancy?', 'Increased caloric needs: +340 kcal/day (2nd trimester), +450 kcal/day (3rd trimester). Key nutrients: folic acid (400–800 mcg neural tube defect prevention), iron (27 mg/day increased blood volume), calcium (1000 mg bone health), iodine (thyroid function), DHA/omega-3 (brain development), vitamin D. Avoid: alcohol (teratogen), high-mercury fish (shark, swordfish), raw/undercooked foods, excess vitamin A.', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'What is anorexia nervosa and its medical complications?', 'A restrictive eating disorder: intense fear of weight gain, distorted body image, and severe caloric restriction leading to dangerously low body weight (BMI <17.5). Complications: electrolyte imbalances (especially hypokalemia), cardiac arrhythmias, bradycardia (leading cause of death from cardiac arrest), amenorrhea, osteoporosis, muscle wasting, lanugo (fine body hair), and cognitive impairment. Highest mortality of any psychiatric disorder.', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'What is bulimia nervosa and its medical complications?', 'An eating disorder with recurrent binge eating followed by compensatory behaviors (self-induced vomiting, laxative/diuretic abuse, excessive exercise). Normal or slightly above-normal weight. Complications: dental erosion (acid from vomiting), parotid gland enlargement, Russell''s sign (calluses on knuckles), esophageal tears (Mallory-Weiss), electrolyte imbalances (hypokalemia from purging → cardiac arrhythmias), metabolic alkalosis.', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'What is sodium''s role and the risks of excess dietary sodium?', 'Sodium regulates extracellular fluid volume, blood pressure (via osmotic pressure), and nerve/muscle function. Major dietary source: processed foods and restaurant meals. Excess sodium: hypertension (increases blood volume and vascular resistance), fluid retention (edema), increased risk of stomach cancer, and kidney disease progression. Recommended: <2,300 mg/day; <1,500 mg/day for hypertensives.', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'What are the nutritional needs of older adults?', 'Increased needs: vitamin D (bone health; decreased skin synthesis), calcium (prevent osteoporosis), vitamin B12 (decreased absorption due to atrophic gastritis/decreased intrinsic factor), fiber (prevent constipation). Decreased needs: total calories (lower BMR and activity level). Protein needs remain the same or increase (prevent sarcopenia). Dehydration risk increases (diminished thirst sensation). Zinc and folate often deficient.', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'What does %DV (Percent Daily Value) mean on food labels?', 'Shows how much of a nutrient one serving contributes to a 2,000 kcal/day diet. ≤5% DV: considered low in that nutrient. ≥20% DV: considered high. Useful for comparing foods and identifying nutrient-dense vs. nutrient-poor choices. The 2020 updated Nutrition Facts panel requires listing added sugars, potassium, and vitamin D (previously optional).', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'What is kwashiorkor?', 'A form of severe protein malnutrition despite adequate caloric intake; most common in children in developing countries after weaning. Characteristics: bilateral pitting edema (from low oncotic pressure/hypoalbuminemia), distended abdomen, muscle wasting, apathy, skin and hair changes (hypopigmentation, dermatosis). Distinguished from marasmus (severe total calorie deficiency → severe wasting, no edema).', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'What are trans fatty acids and why are they harmful?', 'Industrially produced (partially hydrogenated oils) trans fats: raise LDL cholesterol AND lower HDL cholesterol simultaneously → worst effect on cardiovascular risk of any dietary fat. Increase systemic inflammation. FDA banned partially hydrogenated oils in the US (effective 2020). Small amounts of naturally occurring trans fats in ruminant animal products (CLA) are not harmful.', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'What is the role of vitamin K and its clinical importance?', 'Vitamin K is essential for the hepatic synthesis of coagulation factors II (prothrombin), VII, IX, and X (the clotting factors inhibited by warfarin). Also required for bone protein synthesis (osteocalcin). Deficiency: prolonged PT/INR, bleeding risk. Warfarin works by inhibiting vitamin K recycling. Newborns receive vitamin K injection at birth (sterile gut lacks bacterial synthesis; breast milk is low in vitamin K).', 'medium'),
  ('a1000000-0000-0000-0000-000000000005', 'What are the principles of food safety to prevent foodborne illness?', 'Clean: wash hands, surfaces, and produce. Separate: prevent cross-contamination (raw meat from ready-to-eat foods). Cook: cook to safe internal temperatures (poultry 165°F, ground beef 160°F, pork/fish 145°F). Chill: refrigerate within 2 hours (1 hour if >90°F ambient). Common pathogens: Salmonella (poultry/eggs), E. coli O157:H7 (undercooked beef), Listeria (soft cheeses, deli meats), Norovirus (person-to-person).', 'medium');
insert into public.cards (event_id, front, back, difficulty) values
  ('a1000000-0000-0000-0000-000000000005', 'Explain nitrogen balance and its clinical significance.', 'Nitrogen balance = nitrogen intake (from dietary protein) minus nitrogen losses (urine, feces, sweat, wound exudate). Positive balance (intake > loss): anabolism, growth, healing. Negative balance (loss > intake): catabolism in sepsis, burns, critical illness, starvation. Clinical use: assess adequacy of nutritional support in ICU patients. Goal of nutrition therapy: achieve nitrogen equilibrium or positive balance to support tissue repair.', 'hard'),
  ('a1000000-0000-0000-0000-000000000005', 'Describe the metabolic response to starvation.', 'Phase 1 (0–24 hours): glycogen depletion (liver glycogen ~100g, muscle ~400g). Phase 2 (days): gluconeogenesis from amino acids (muscle protein catabolism) and glycerol maintains blood glucose for brain. Phase 3 (weeks): ketosis — liver converts free fatty acids to ketone bodies (beta-hydroxybutyrate, acetoacetate) → brain adapts to use ketones as primary fuel (protein-sparing adaptation). Late starvation: continued muscle wasting, immune failure, cardiac muscle loss.', 'hard'),
  ('a1000000-0000-0000-0000-000000000005', 'What is enteral nutrition and when is it preferred over parenteral?', 'Enteral nutrition (EN): delivery of nutrients via feeding tube (nasogastric, nasoduodenal, gastrostomy/G-tube, jejunostomy/J-tube) directly into the GI tract. Preferred when the gut is functional because: maintains gut mucosal integrity (prevents atrophy and bacterial translocation), lower infection risk than TPN, lower cost, and more physiological. "When in doubt, use the gut."', 'hard'),
  ('a1000000-0000-0000-0000-000000000005', 'What is total parenteral nutrition (TPN) and its complications?', 'TPN delivers all nutrients intravenously via central catheter (peripheral PN for short-term, lower concentrations). Contains: dextrose, amino acids, lipid emulsions, electrolytes, vitamins, trace elements. Complications: catheter-related bloodstream infection (CLABSI), hyperglycemia, refeeding syndrome, hepatic steatosis (fatty liver), metabolic acidosis, and gut atrophy from disuse (↑bacterial translocation risk).', 'hard'),
  ('a1000000-0000-0000-0000-000000000005', 'What is refeeding syndrome and how is it prevented?', 'A potentially fatal metabolic complication occurring when nutrition is reintroduced too rapidly after prolonged starvation/malnutrition. Mechanism: refeeding triggers insulin release → cellular uptake of phosphate, potassium, and magnesium → profound hypophosphatemia (most dangerous, causes respiratory failure, heart failure, hemolysis), hypokalemia, hypomagnesemia. Prevention: identify at-risk patients (severe malnutrition, anorexia, alcoholism, prolonged NPO), replete electrolytes before starting, advance nutrition slowly (start at 10–20 kcal/kg/day), monitor electrolytes frequently.', 'hard'),
  ('a1000000-0000-0000-0000-000000000005', 'Explain the role of the liver in lipid metabolism.', 'The liver is the central hub of lipid metabolism: synthesizes cholesterol (via HMG-CoA reductase — target of statins), packages triglycerides into VLDLs for export to peripheral tissues, produces HDL, synthesizes bile acids from cholesterol (for fat digestion), performs beta-oxidation of fatty acids for energy, performs de novo lipogenesis (excess carbohydrate → fat), and metabolizes chylomicron remnants.', 'hard'),
  ('a1000000-0000-0000-0000-000000000005', 'Explain the biochemistry of protein digestion and absorption.', 'Stomach: pepsinogen activated to pepsin by HCl → begins protein denaturation and cleavage. Small intestine: pancreatic endoproteases (trypsin, chymotrypsin, elastase) cleave interior peptide bonds; exopeptidases (carboxypeptidase, aminopeptidase) cleave terminal amino acids. Brush-border peptidases cleave di/tripeptides → individual amino acids absorbed by Na+-coupled active transport. Enter portal circulation → liver.', 'hard'),
  ('a1000000-0000-0000-0000-000000000005', 'What is the biochemical basis of lactose intolerance?', 'Deficiency (partial or complete) of lactase (beta-galactosidase) in small intestinal brush-border cells. Without lactase, lactose cannot be hydrolyzed into glucose + galactose for absorption → undigested lactose passes to colon → fermented by colonic bacteria → gas (CO2, H2, methane) causing bloating, flatulence, cramps → osmotic diarrhea. Primary lactose intolerance is the global norm; persistence of lactase activity into adulthood is a genetic trait more common in Northern Europeans.', 'hard'),
  ('a1000000-0000-0000-0000-000000000005', 'Describe the metabolic consequences of obesity and metabolic syndrome.', 'Expanded visceral adipose tissue acts as an endocrine organ releasing pro-inflammatory adipokines (TNF-α, IL-6, leptin) and free fatty acids → systemic inflammation, insulin resistance, ectopic fat deposition (liver → NAFLD, muscle). Metabolic syndrome criteria (any 3 of 5): central obesity (waist >40 in men, >35 in women), high TG (≥150), low HDL, hypertension, fasting glucose ≥100 mg/dL. Dramatically increases cardiovascular disease and type 2 diabetes risk.', 'hard'),
  ('a1000000-0000-0000-0000-000000000005', 'Explain the role of antioxidants in preventing chronic disease.', 'Reactive oxygen species (ROS, free radicals) are produced during normal metabolism and by environmental exposures. Excess ROS causes oxidative stress → DNA damage (carcinogenesis), lipid peroxidation (LDL oxidation → atherosclerosis), protein oxidation. Antioxidants neutralize ROS: enzymatic (SOD, catalase, glutathione peroxidase) and dietary (vitamin C, vitamin E, selenium, carotenoids, polyphenols from fruits and vegetables). Epidemiological studies support high dietary antioxidant intake for reduced cancer and CVD risk.', 'hard'),
  ('a1000000-0000-0000-0000-000000000005', 'Describe phenylketonuria (PKU) and its nutritional management.', 'Autosomal recessive deficiency of phenylalanine hydroxylase (PAH) → inability to convert phenylalanine (Phe) to tyrosine → Phe accumulates → neurotoxic → intellectual disability, seizures, and fair pigmentation (tyrosine needed for melanin). Diagnosed by newborn screening. Management: lifelong strict low-phenylalanine diet (avoid high-protein foods), phenylalanine-free medical formula providing all other amino acids, supplemental tyrosine. Sapropterin (BH4 cofactor) helps ~25% of patients.', 'hard'),
  ('a1000000-0000-0000-0000-000000000005', 'What is the difference between AMDR recommendations for the general population vs. a patient with type 2 diabetes?', 'General AMDR: Carbohydrates 45–65%, Fat 20–35%, Protein 10–35% of total calories. Type 2 Diabetes: No universal carbohydrate percentage; generally reduced to 45–60 g per meal with emphasis on low-GI, high-fiber complex carbohydrates; limiting refined sugars and sugary beverages. Protein at moderate levels; fat quality emphasized (unsaturated preferred, limit saturated/trans). Mediterranean and low-carbohydrate diets have strong evidence for glycemic improvement.', 'hard'),
  ('a1000000-0000-0000-0000-000000000005', 'What is non-alcoholic fatty liver disease (NAFLD) and its nutritional management?', 'NAFLD: excess fat (>5% of hepatocytes) in the liver not caused by alcohol, medications, or other specific diseases. Strongly linked to obesity, insulin resistance, dyslipidemia. Spectrum: simple steatosis → NASH (with inflammation/hepatocyte injury) → fibrosis → cirrhosis → hepatocellular carcinoma. Nutritional management: 7–10% weight loss (most effective), Mediterranean diet (reduces hepatic fat), limit fructose and added sugars (fructose drives hepatic de novo lipogenesis), omega-3 supplementation, avoid alcohol, regular aerobic exercise.', 'hard'),
  ('a1000000-0000-0000-0000-000000000005', 'Describe the role of the gut microbiome in nutrition and health.', 'The gut microbiome (~38 trillion bacteria, primarily in the colon) ferments undigested dietary fiber → short-chain fatty acids (SCFAs: butyrate, propionate, acetate). Butyrate is the primary colonocyte fuel and has anti-inflammatory effects. The microbiome influences: energy harvest from food (dysbiosis linked to obesity), immune system development and regulation, mental health (gut-brain axis via vagus nerve and serotonin), and drug metabolism. Diet is the most powerful modulator of microbiome composition.', 'hard'),
  ('a1000000-0000-0000-0000-000000000005', 'Explain the concept of nutrient-drug interactions and give three clinical examples.', 'Nutrients can alter drug absorption, metabolism, or efficacy — and vice versa. Examples: (1) Grapefruit juice inhibits CYP3A4 → increases blood levels of statins, calcium channel blockers, immunosuppressants → toxicity risk. (2) Vitamin K-rich foods (leafy greens) antagonize warfarin anticoagulation → need consistent K intake. (3) Tyramine-rich foods (aged cheeses, cured meats) with MAO inhibitors → hypertensive crisis. (4) Calcium/iron supplements reduce absorption of tetracyclines and fluoroquinolones — take 2 hours apart.', 'hard');
insert into public.cards (event_id, front, back, difficulty) values
  ('a1000000-0000-0000-0000-000000000006', 'What does BSI stand for and why is it the first step in patient assessment?', 'Body Substance Isolation: treating all blood and body fluids as potentially infectious regardless of known diagnosis. Always establish BSI (gloves, mask, eye protection, gown as needed) before approaching any patient to protect yourself and prevent cross-contamination.', 'easy'),
  ('a1000000-0000-0000-0000-000000000006', 'What is the primary survey in EMS patient assessment?', 'A rapid, systematic assessment to identify and immediately treat life threats: Airway (open and maintain), Breathing (rate, quality, adequacy), Circulation (pulse, bleeding control, skin), Disability (level of consciousness via AVPU/GCS), Expose/Environment (remove clothing, prevent hypothermia).', 'easy'),
  ('a1000000-0000-0000-0000-000000000006', 'What does AVPU stand for?', 'Alert (responds normally, oriented), Verbal (responds only when spoken to), Pain (responds only to painful stimulus), Unresponsive (no response to any stimulus). A rapid LOC assessment tool; GCS provides more detailed scoring.', 'easy'),
  ('a1000000-0000-0000-0000-000000000006', 'What are normal vital sign ranges for an adult?', 'HR: 60–100 bpm. RR: 12–20 breaths/min. BP: systolic 90–120 mmHg, diastolic 60–80 mmHg. SpO2: 95–100%. Temperature: 36.5–37.5°C (97.7–99.5°F). Skin: warm, pink, dry.', 'easy'),
  ('a1000000-0000-0000-0000-000000000006', 'What does SAMPLE stand for in patient history taking?', 'Signs and Symptoms (chief complaint), Allergies (medications, foods, environment), Medications (prescribed and OTC), Pertinent past medical history, Last oral intake, Events leading to the emergency. Gathered during secondary survey.', 'easy'),
  ('a1000000-0000-0000-0000-000000000006', 'What is the correct sequence for adult CPR per AHA guidelines?', 'C-A-B: Compressions first (30 at rate of 100–120/min, depth ≥2 inches/5 cm, full recoil), then Airway (head-tilt chin-lift), then Breathing (2 rescue breaths over 1 second each). 30:2 ratio. Minimize interruptions. Use AED as soon as available.', 'easy'),
  ('a1000000-0000-0000-0000-000000000006', 'How do you control severe external bleeding?', 'Apply firm direct pressure with a gloved hand and clean dressing. Maintain continuous pressure (10–15 minutes without peeking). For life-threatening limb bleeding uncontrolled by pressure: apply tourniquet 2–3 inches above the wound; note time. For junctional (groin, axilla, neck) wounds: wound packing with hemostatic gauze.', 'easy'),
  ('a1000000-0000-0000-0000-000000000006', 'What is triage?', 'The process of sorting and prioritizing patients in a mass casualty incident based on the severity of their injuries and likelihood of survival with available resources. Goal: do the greatest good for the greatest number. EMTs use START (Simple Triage and Rapid Treatment) triage in the field.', 'easy'),
  ('a1000000-0000-0000-0000-000000000006', 'What does the acronym FAST stand for in stroke recognition?', 'Face drooping (one side droops, uneven smile), Arm weakness (one arm drifts down), Speech difficulty (slurred, strange, or absent), Time to call 911 (note time of symptom onset — critical for tPA eligibility). Also add "BE-FAST": Balance and Eyes (sudden vision change).', 'easy'),
  ('a1000000-0000-0000-0000-000000000006', 'What is the rule of nines for estimating burn surface area in adults?', 'Head and neck: 9%, Each arm: 9%, Anterior trunk: 18%, Posterior trunk: 18%, Each leg: 18%, Perineum/genitalia: 1% = 100% TBSA. Used to estimate fluid resuscitation needs. For children, the head is proportionally larger (Lund-Browder chart more accurate).', 'easy'),
  ('a1000000-0000-0000-0000-000000000006', 'What does AED stand for and how does it work?', 'Automated External Defibrillator. Delivers a controlled electrical shock to the heart to terminate ventricular fibrillation (VF) or pulseless ventricular tachycardia (pVT) and allow normal conduction to resume. Follow voice prompts: power on, attach pads, analyze rhythm, deliver shock (if advised), resume CPR immediately.', 'easy'),
  ('a1000000-0000-0000-0000-000000000006', 'What is the difference between a sign and a symptom in EMS?', 'Sign: an objective, observable finding identified by the EMT (e.g., cyanosis, diaphoresis, tachycardia). Symptom: a subjective experience reported by the patient (e.g., "I can''t breathe," "my chest hurts"). Both are gathered in the patient history and physical exam.', 'easy'),
  ('a1000000-0000-0000-0000-000000000006', 'What are the burn classifications by depth?', 'Superficial (1st degree): epidermis only; red, dry, painful (e.g., sunburn). Partial thickness (2nd degree): epidermis + part of dermis; blistered, wet, very painful. Full thickness (3rd degree): all skin layers; dry, leathery, waxy white/brown/black; painless (nerve destruction). Fourth degree: bone, muscle, tendon involvement.', 'easy'),
  ('a1000000-0000-0000-0000-000000000006', 'What is the recovery position and when is it used?', 'Left lateral decubent position (patient on left side, top knee bent forward). Used for: unconscious patients who are breathing adequately and have no suspected spinal injury. Prevents airway obstruction by the tongue and aspiration of vomit.', 'easy'),
  ('a1000000-0000-0000-0000-000000000006', 'What are the 2-rescuer CPR ratios for adults, children, and infants?', 'Adults: 30 compressions : 2 breaths. Children (1 year to puberty) with 2 rescuers: 15 compressions : 2 breaths. Infants (<1 year) with 2 rescuers: 15 compressions : 2 breaths, using 2-finger or 2-thumb-encircling technique. For intubated patients: asynchronous — 100–120/min compressions without pausing for breaths.', 'easy');
insert into public.cards (event_id, front, back, difficulty) values
  ('a1000000-0000-0000-0000-000000000006', 'Describe the complete ABCDE primary survey for a trauma patient.', 'A: Airway — open airway (jaw thrust if trauma suspected), C-spine immobilization, suction if needed. B: Breathing — assess rate, depth, bilateral breath sounds, work of breathing; apply O2. C: Circulation — assess pulse (rate, quality), skin color/temp/moisture, control major bleeding, establish IV access. D: Disability — AVPU, GCS, pupils, blood glucose. E: Expose — remove all clothing to identify all injuries; maintain body temperature.', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'Describe OPQRST pain assessment.', 'Onset: when did it start? Gradual or sudden? Provocation/Palliation: what makes it better or worse? Quality: describe it (sharp, dull, pressure, burning, tearing). Region/Radiation: where exactly? Does it spread to shoulder, arm, jaw? Severity: rate 0–10. Time: how long has it lasted? Constant or intermittent?', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'What are the four types of shock and their mechanisms?', 'Hypovolemic: absolute loss of blood/fluid volume (hemorrhage, dehydration, burns). Cardiogenic: heart pump failure (large MI, severe arrhythmia, tamponade). Distributive: pathological vasodilation/maldistribution (Septic: infection-mediated; Anaphylactic: IgE-mediated; Neurogenic: spinal cord injury with loss of sympathetic tone). Obstructive: mechanical obstruction to cardiac output (tension pneumothorax, pulmonary embolism, cardiac tamponade).', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'What are the signs and symptoms of hypovolemic shock in progression?', 'Compensated (early): tachycardia (first sign), anxiety, slight increase in RR, skin pale/cool/slightly moist, normal BP. Decompensated: falling BP (hypotension), marked tachycardia, tachypnea, delayed CRT >2 sec, altered mental status (confusion). Irreversible (late): profound hypotension, bradycardia, mottled skin, unresponsiveness. Hypotension is a LATE sign in healthy adults.', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'Describe the head-tilt chin-lift and jaw thrust maneuvers.', 'Head-tilt chin-lift: tilt head back (extension of neck) while lifting chin upward; moves tongue from posterior pharynx. Contraindicated with suspected cervical spine injury. Jaw thrust: place fingertips behind the jaw angles and push the mandible forward without moving the neck; preferred airway maneuver when trauma is suspected.', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'What is an OPA (oropharyngeal airway) and how do you select the correct size?', 'A curved, rigid plastic adjunct inserted into the mouth to lift the base of the tongue from the posterior pharynx, maintaining airway patency. Use ONLY in unconscious patients WITHOUT a gag reflex. Size selection: measure from the corner of the mouth to the earlobe, OR from the center of the mouth to the angle of the jaw.', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'What is an NPA (nasopharyngeal airway) and when is it preferred over an OPA?', 'A soft, flexible rubber tube inserted through the nostril into the nasopharynx. Can be used in conscious, semiconscious, or unconscious patients WITH an intact gag reflex. Preferred when: patient has a gag reflex (OPA would cause vomiting), trismus (clenched jaw), dental trauma, or is combative. Size: measure from tip of nose to earlobe. Lubricate well; insert with bevel toward septum.', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'What is the Glasgow Coma Scale and what score indicates need for airway intervention?', 'GCS assesses: Eye Opening (1–4), Verbal Response (1–5), Motor Response (1–6). Score range: 3 (lowest) to 15 (normal). GCS ≤8: severe brain injury; patient cannot protect own airway → intubation indicated. GCS 9–12: moderate injury. GCS 13–15: minor injury. Used to track neurological trends.', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'What are the signs and management of tension pneumothorax?', 'Signs: absent breath sounds on affected side, tracheal deviation away from injury (late sign), JVD, hypotension, tachycardia, severe respiratory distress, cyanosis. Mechanism: air enters pleural space through one-way valve → lung collapses → mediastinum shifts → compresses great veins and contralateral lung → obstructive shock. Treatment: needle decompression at 2nd intercostal space, midclavicular line; finger thoracostomy for ALS providers.', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'Describe Beck''s triad and the management of pericardial tamponade.', 'Beck''s triad: Hypotension + Muffled (distant) heart sounds + Jugular Venous Distension (JVD). Pericardial tamponade: blood accumulates in pericardial sac → compresses heart → reduced filling → reduced cardiac output → obstructive shock. EMT management: rapid recognition, high-flow O2, IV access, immediate transport; pericardiocentesis (ALS/hospital) is definitive treatment.', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'What is the EMT management of anaphylaxis?', 'Epinephrine 0.3 mg IM (anterolateral thigh using auto-injector or 1:1,000 concentration) — first-line, life-saving intervention. Remove the trigger. High-flow O2. Position supine with legs elevated (or sitting up if dyspnea). Establish IV access. Fluid bolus for hypotension. Diphenhydramine (antihistamine) and corticosteroids (adjuncts). Repeat epinephrine every 5–15 minutes if needed. Immediate transport — reactions can be biphasic.', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'Compare ischemic and hemorrhagic stroke in terms of field management.', 'Ischemic (85%): arterial occlusion by thrombus or embolism → neuron death. Eligible for tPA within 3–4.5 hours of symptom onset (contraindicated if hemorrhagic). Hemorrhagic (15%): vessel rupture → bleeding into/around brain; tPA contraindicated. EMTs CANNOT differentiate in the field. Management for both: FAST recognition, note exact time of symptom onset, O2 if hypoxic, IV access, blood glucose check, rapid transport to stroke center — time is brain (~1.9 million neurons/minute lost).', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'Describe the assessment and management of hypoglycemia vs. hyperglycemia.', 'Hypoglycemia (<70 mg/dL): rapid onset (minutes), diaphoresis, tremors, hunger, altered MS, possible seizure/coma. Treat: oral glucose if alert, glucagon IM/IN, or IV D50W. Hyperglycemia (>250 mg/dL): gradual onset (hours-days), polyuria, polydipsia, fruity breath (DKA: ketoacidosis), Kussmaul respirations (deep/rapid), nausea. Treat: IV fluids, transport; definitive treatment (insulin) in-hospital. ALWAYS check BG in altered mental status.', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'What are the pediatric vital sign ranges and why do they matter for EMTs?', 'Newborn: HR 100–160, RR 30–60. 1 year: HR 80–140, RR 24–40. 5 years: HR 70–120, RR 20–30. 10 years: HR 60–100, RR 15–25. Key principle: children compensate effectively (maintaining normal BP) until sudden decompensation. Tachycardia and increased RR are the earliest and most reliable signs of shock in pediatric patients. Bradycardia in a sick child is a pre-arrest finding.', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'What is the Parkland formula for burn fluid resuscitation?', '4 mL × weight (kg) × % TBSA burned = total LR (lactated Ringer''s) in first 24 hours from time of burn. Administer: first half in the first 8 hours (from time of burn, not arrival), second half over next 16 hours. Do NOT use colloids in first 24 hours. Monitor urine output (goal: 0.5–1 mL/kg/hr in adults, 1 mL/kg/hr in children) to guide adequacy.', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'Describe spinal immobilization principles and when to apply them.', 'Indications: any trauma with mechanism capable of causing spinal injury (MVC, falls from height, diving accidents, sports injuries, penetrating trauma near spine). Technique: manual in-line stabilization first, then cervical collar (proper sizing), movement to long backboard with head blocks and straps, or scoop stretcher. Evidence-based trend: selective spinal immobilization (alert, cooperative patients with no midline tenderness and no neurological deficits may not require backboard).', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'Describe the four classes of hemorrhage and corresponding presentation.', 'Class I (<750 mL, <15%): minimal signs — slight anxiety, RR normal, HR slightly elevated, BP normal. Class II (750–1500 mL, 15–30%): tachycardia (>100), increased RR, narrowed pulse pressure, anxious. Class III (1500–2000 mL, 30–40%): marked tachycardia (>120), tachypnea (>30), BP falling, altered mental status. Class IV (>2000 mL, >40%): immediately life-threatening, profound hypotension, bradycardia may occur, very pale, obtunded. Treat Class III/IV as hemorrhagic shock.', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'Describe the management of a seizing patient in the field.', 'Protect from injury (clear area, pad head, do not restrain). Do NOT put anything in the mouth. Position on side after cessation (recovery position) to prevent aspiration. Time the seizure duration. Establish IV/IO access. Check blood glucose. Diazepam (0.1 mg/kg IV/IO or 0.5 mg/kg rectal) or midazolam (IM/IN per protocol) for status epilepticus. High-flow O2. Rapid transport for: first seizure, prolonged (>5 min), no recovery, known cause needing treatment (hypoglycemia, eclampsia).', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'What legal and ethical principles govern EMT practice?', 'Consent: expressed (patient verbally/written agrees), implied (unconscious or legally incompetent patients — assumed to consent), minor consent (parent/legal guardian required; or emancipated minor). Refusal of care: a competent adult has the right to refuse treatment; document extensively, have patient sign refusal form, offer to call back. Negligence: 4 elements — duty to act, breach of duty, causation, damages. Abandonment: unilaterally terminating care without transferring to equal or higher level provider. Good Samaritan laws: protect off-duty providers acting in good faith.', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'What is an open chest wound (sucking chest wound) and how is it treated?', 'An open pneumothorax: penetrating chest trauma creates an opening in the chest wall through which air enters the pleural space during inspiration (sucking sound), disrupting negative intrathoracic pressure and preventing lung inflation. Treatment: apply a commercial vented (three-sided) chest seal over the wound. A three-sided occlusive dressing (tape three sides) allows air to escape on expiration but prevents entry on inspiration. Monitor for conversion to tension pneumothorax — burp or remove seal if develops.', 'medium'),
  ('a1000000-0000-0000-0000-000000000006', 'What is the pediatric assessment triangle (PAT) and how is it used?', 'A rapid across-the-room initial assessment tool: Appearance (TICLS mnemonic: Tone, Interactivity, Consolability, Look/Gaze, Speech/cry) — assesses brain perfusion and oxygenation. Work of Breathing (retractions, nasal flaring, grunting, positioning, stridor, wheeze) — assesses respiratory effort. Circulation (skin color: pallor, cyanosis, mottling) — assesses perfusion. Completed in 30–60 seconds before touching the child. Determines urgency of intervention.', 'medium');
insert into public.cards (event_id, front, back, difficulty) values
  ('a1000000-0000-0000-0000-000000000006', 'What is distributive shock and how does its treatment differ from hypovolemic shock?', 'In distributive shock (septic, anaphylactic, neurogenic), the problem is pathological vasodilation causing maldistribution of blood flow — circulating volume may be adequate but distributed inappropriately. Unlike hypovolemic shock (true volume loss), distributive shock requires vasopressors (norepinephrine) in addition to IV fluid resuscitation. Anaphylactic: epinephrine IM first. Neurogenic: IV fluids plus vasopressors. Septic: aggressive fluid resuscitation (30 mL/kg), antibiotics, vasopressors if unresponsive.', 'hard'),
  ('a1000000-0000-0000-0000-000000000006', 'Explain the complete pathophysiology of tension pneumothorax and why it is fatal without intervention.', 'Penetrating trauma or rib fracture creates a one-way valve in the pleural space (or lung). Air enters on inspiration but cannot exit. Progressive accumulation increases intrapleural pressure → ipsilateral lung collapses → mediastinum shifts contralaterally → kinks SVC (impairs venous return to right heart) → kinks contralateral lung → RV cannot fill → cardiac output collapses → obstructive shock → cardiac arrest. Fatal within minutes without emergent needle decompression (2nd ICS, MCL) releasing trapped air.', 'hard'),
  ('a1000000-0000-0000-0000-000000000006', 'Describe the pathophysiology and EMT management of cardiogenic shock.', 'Massive MI (usually LAD occlusion affecting anterior LV) → severe reduction in contractility → ↓stroke volume → ↓cardiac output → organ hypoperfusion (forward failure) + pulmonary edema (backward failure). Compensatory SNS activation worsens myocardial O2 demand on already failing heart. EMT management: O2 (CPAP for pulmonary edema), IV access, 12-lead ECG, aspirin 324 mg (chew) if ACS suspected, avoid aggressive fluids (worsens pulmonary edema), vasopressor support (dopamine per protocol), rapid transport to PCI-capable center — "time is muscle."', 'hard'),
  ('a1000000-0000-0000-0000-000000000006', 'What are the H''s and T''s of cardiac arrest and how does an EMT use them?', 'Reversible causes of cardiac arrest: H''s: Hypovolemia (IVF), Hypoxia (ventilation/O2), Hydrogen ion/acidosis (ventilation), Hypo/Hyperkalemia (IV fluid), Hypothermia (warm). T''s: Tension pneumothorax (needle decompression), Tamponade (pericardiocentesis), Toxins (antidote/supportive), Thrombosis-Pulmonary (thrombolytics), Thrombosis-Coronary (PCI). EMTs identify and treat what''s in their scope (hypovolemia, hypoxia, tension PTX); the rest guide rapid transport decision.', 'hard'),
  ('a1000000-0000-0000-0000-000000000006', 'Describe assessment and management of a patient with signs of increasing intracranial pressure.', 'Early ICP: headache, nausea, vomiting (projectile), altered mental status. Late ICP/Cushing''s Triad (herniation imminent): hypertension (widened pulse pressure) + bradycardia + irregular respirations. Unilateral dilated, fixed pupil indicates ipsilateral uncal herniation. EMT management: elevate HOB 30° (if spinal clearance allows), high-flow O2 targeting SpO2 94–98% (hyperoxia can worsen), avoid hypercapnia (aim ETCO2 35–40 mmHg with capnography), minimize stimulation, rapid transport to trauma center, consider controlled hyperventilation (ETCO2 30–35) only if signs of herniation.', 'hard'),
  ('a1000000-0000-0000-0000-000000000006', 'Describe crush syndrome: assessment, pathophysiology, and prehospital management.', 'Prolonged compression (>1 hour) of muscle → rhabdomyolysis. Upon extrication: myoglobin (nephrotoxic), potassium (cardiac arrest risk), phosphate, and CK flood the circulation. Hyperkalemia can cause VF before or during extrication ("extrication death"). Myoglobin precipitates in renal tubules → AKI. Management: establish large-bore IV access BEFORE extrication; aggressive fluid resuscitation (1–1.5 L LR per hour) to maintain urine output >300 mL/hr; cardiac monitoring for hyperkalemia (peaked T waves, wide QRS); sodium bicarbonate to alkalinize urine (reduces myoglobin precipitation); rapid transport.', 'hard'),
  ('a1000000-0000-0000-0000-000000000006', 'Explain injury patterns predicted by vehicle crash mechanism.', 'Frontal impact: occupant continues forward → steering wheel/dash impact → chest/abdomen (aortic injury, pneumothorax), femur fractures (dashboard knee), cervical flexion. Lateral (T-bone): lateral thoracic/abdominal injuries, pelvic fracture, ipsilateral clavicle/humerus. Rear-end: cervical hyperextension (whiplash), cervical spine fracture if headrest absent. Rollover: highest severity; multiple patterns; ejection risk × 8 mortality. Unrestrained occupants: 5× mortality. Index of suspicion guides secondary survey.', 'hard'),
  ('a1000000-0000-0000-0000-000000000006', 'Describe START triage in a mass casualty incident.', 'START (Simple Triage and Rapid Treatment): 30 seconds per patient. Step 1: instruct walking wounded to move to designated area → tag Green (Minor). Step 2: non-walking patients — open airway if needed. If no respirations after airway opening → tag Black (Deceased). If RR >30 or <10 → tag Red (Immediate). If radial pulse absent or CRT >2 sec → tag Red. If cannot follow simple commands → tag Red. Otherwise → tag Yellow (Delayed). Rescuers perform only: airway opening, hemorrhage control, and PPV (1 rescuer for apnea).', 'hard'),
  ('a1000000-0000-0000-0000-000000000006', 'Describe the pharmacology, indications, contraindications, and administration of nitroglycerin in the field.', 'Mechanism: vasodilator (primarily venous) → reduces myocardial preload and afterload → reduces myocardial oxygen demand. Indication: chest pain suspected ACS; patient has own prescription. Contraindications: systolic BP <90 mmHg, HR <50 or >100, inferior MI with suspected RV involvement, erectile dysfunction medications (PDE5 inhibitors: sildenafil, tadalafil — causes life-threatening hypotension) within 24–48 hours. Dose: 0.4 mg SL tablet or spray q5 min × 3, reassessing BP before each dose. Side effects: hypotension, headache, tachycardia.', 'hard'),
  ('a1000000-0000-0000-0000-000000000006', 'What is the clinical presentation and EMT management of epiglottitis?', 'Epiglottitis: acute bacterial inflammation (H. influenzae type b, Streptococcus) of the epiglottis causing rapid, severe swelling and potential complete airway obstruction. Classic presentation (adult or non-vaccinated child): sudden high fever, severe sore throat, drooling (dysphagia), muffled "hot potato" voice, inspiratory stridor, tripod positioning (leaning forward, neck extended). CRITICAL: Do NOT examine the throat, obtain cultures, or agitate the patient — any stimulus can cause complete obstruction. Allow position of comfort. Humidified O2. Call ahead to hospital. Immediate transport to ED with surgical airway capability.', 'hard'),
  ('a1000000-0000-0000-0000-000000000006', 'Describe assessment and management of a patient with suspected pelvic fracture.', 'High-energy mechanism required (MVC, crush, fall from height). Signs: pain on palpation of iliac crests (SINGLE rock of pelvis — do not repeat), leg length discrepancy, rotational deformity, hematoma over pelvic area, urethral blood. Pelvic fractures can cause 2–6 L blood loss into retroperitoneal space from pelvic venous plexus. Management: DO NOT rock the pelvis repeatedly. Apply commercial pelvic binder (or sheet) at level of greater trochanters to tamponade bleeding. Two large-bore IVs. Fluid resuscitation (permissive hypotension: systolic 80–90 mmHg in penetrating trauma). Rapid transport. This is a trauma center emergency.', 'hard'),
  ('a1000000-0000-0000-0000-000000000006', 'What is the pathophysiology and recognition of acute coronary syndrome (ACS) and the EMT management?', 'ACS spectrum: unstable angina, NSTEMI, STEMI — all from atherosclerotic plaque rupture → coronary thrombus. STEMI: complete occlusion → full-thickness infarct. Symptoms: chest pressure/tightness (may radiate to left arm, jaw, back), diaphoresis, nausea, dyspnea, anxiety. Atypical (women, elderly, diabetics): fatigue, nausea without chest pain. EMT management: position of comfort, high-flow O2 if SpO2 <94%, aspirin 324 mg chewed, NTG (if indicated), 12-lead ECG (activate cath lab en route for STEMI), IV access, transport to PCI-capable center. "Time = Myocardium" — door-to-balloon goal <90 minutes.', 'hard'),
  ('a1000000-0000-0000-0000-000000000006', 'Describe pediatric respiratory failure: recognition and EMT management.', 'Respiratory failure in children: initially tachypnea, retractions (subcostal, intercostal, suprasternal), nasal flaring, head bobbing, grunting (auto-PEEP), stridor or wheeze, SpO2 <94%. Compensated to decompensated transition is RAPID in children — do not wait for cyanosis. Management: DO NOT agitate child (worsens obstruction). Allow position of comfort (sniffing position for infants). O2 via NRB or blow-by (for mask-intolerant children). BVM ventilation if inadequate effort. Nebulized albuterol for bronchospasm (asthma). Nebulized epinephrine for croup. Anticipate intubation — call ahead.', 'hard'),
  ('a1000000-0000-0000-0000-000000000006', 'Describe the assessment and management of an evisceration.', 'Evisceration: abdominal organs protrude through an open wound. DO NOT attempt to push organs back into the abdomen (risk of contamination, tissue damage, vagal response). Cover eviscerated organs with a sterile, saline-moistened dressing (keeps organs moist and viable) then cover with a dry sterile dressing or occlusive wrap to maintain moisture and temperature. Keep patient supine with knees flexed (relieves abdominal tension). NPO. Two large-bore IVs. Avoid unnecessary abdominal palpation. Immediate transport to trauma center. Monitor for shock.', 'hard'),
  ('a1000000-0000-0000-0000-000000000006', 'Describe documentation requirements for an EMT patient care report (PCR).', 'A PCR is a legal document and medical record. Must include: patient demographics (age, sex, DOB), chief complaint, history (SAMPLE, OPQRST), physical exam findings, vital signs (all sets with times), treatments administered (drug, dose, route, time, response), changes in patient condition, disposition (transport, destination, patient status), and crew information. Accurate, objective, and timely documentation is essential for: continuity of care, legal protection, quality improvement, billing, and research. "If it wasn''t documented, it wasn''t done."', 'hard');
